}

func TestClientServer_Signal(t *testing.T) {
    // Start long-running process
    // Send SIGTERM via client
    // Verify process terminates
}

func TestClientServer_ConcurrentCommands(t *testing.T) {
    // Start multiple commands simultaneously
    // Verify all complete correctly with isolated I/O
}
```

### 3. Platform Integration Tests

**`sandbox/runtime_linux_test.go`** (build tag: `//go:build linux`)
```go
func TestLinuxRuntime_CreateVM(t *testing.T) {
    // Requires KVM - skip if not available
