Matchlock provides:
- Firecracker microVM management (Linux)
- Apple Virtualization.framework (macOS arm64)
- FUSE workspace mounting over vsock
- Guest agent infrastructure
- Network allowlisting
- Secret injection via MITM proxy

We wrap their SDK to implement our `Runtime` interface.

## Testing Strategy

### 1. Unit Tests: `sandbox/executor_test.go`

Table-driven tests where inputs/outputs can be cleanly encoded:

```go
func TestExecutor_Start(t *testing.T) {
    mock := sandboxtest.NewMockRuntime()
    exec, err := New(context.Background(), Config{}, WithRuntime(mock))
    require.NoError(t, err)
    defer exec.Close()

    tsuite := []struct {
        name    string
        cmd     workspaceapi.Cmd
        wantErr error
    }{
        {name: "simple echo", cmd: workspaceapi.Cmd{Path: "/bin/echo", Args: []string{"hello"}}},
        {name: "with env", cmd: workspaceapi.Cmd{Path: "/usr/bin/env", Env: []string{"FOO=bar"}}},
        {name: "with working dir", cmd: workspaceapi.Cmd{Path: "ls", Dir: "/tmp"}},
        {name: "empty path", cmd: workspaceapi.Cmd{}, wantErr: ErrInvalidCommand},
    }

    for _, tc := range tsuite {
        t.Run(tc.name, func(t *testing.T) {
            pid, err := exec.Start(context.Background(), tc.cmd)
            if tc.wantErr != nil {
                require.ErrorIs(t, err, tc.wantErr)
                return
            }
            require.NoError(t, err)
            assert.NotZero(t, pid)
        })
    }
}

func TestExecutor_Signal(t *testing.T) {
    tsuite := []struct {
        name    string
        pid     workspaceapi.Pid
        sig     syscall.Signal
        wantErr error
    }{
        {name: "SIGTERM valid pid", pid: 1234, sig: syscall.SIGTERM},
        {name: "SIGKILL valid pid", pid: 1234, sig: syscall.SIGKILL},
        {name: "invalid pid", pid: 0, sig: syscall.SIGTERM, wantErr: ErrProcessNotFound},
    }
    // ...
}
```

