### 4. End-to-End Security Tests: `sandbox/e2e_test.go`

Tests that verify ALL security features. Table-driven where inputs/validation are similar:

```go
// Resource limits - table-driven (same setup, parameterized limits)
func TestE2E_ResourceLimits(t *testing.T) {
    tsuite := []struct {
        name      string
        resources ResourceConfig
        cmd       string
        wantErr   string
    }{
        {
            name:      "memory limit OOM",
            resources: ResourceConfig{MemoryMB: 64},
            cmd:       "stress --vm 1 --vm-bytes 128M",
            wantErr:   "killed",
        },
        {
            name:      "disk quota exceeded",
            resources: ResourceConfig{DiskMB: 10},
            cmd:       "dd if=/dev/zero of=/tmp/big bs=1M count=20",
            wantErr:   "No space left",
        },
    }

    for _, tc := range tsuite {
        t.Run(tc.name, func(t *testing.T) {
            exec := setupSandbox(t, Config{Resources: &tc.resources})
            defer exec.Close()
            _, stderr := runCommand(t, exec, tc.cmd)
            assert.Contains(t, stderr, tc.wantErr)
        })
    }
}

// Network policy - table-driven (parameterized allowlist)
func TestE2E_NetworkPolicy(t *testing.T) {
    tsuite := []struct {
        name         string
        allowedHosts []string
        targetHost   string
        wantAllowed  bool
    }{
        {name: "default deny", allowedHosts: nil, targetHost: "example.com", wantAllowed: false},
        {name: "allowed host", allowedHosts: []string{"api.github.com"}, targetHost: "api.github.com", wantAllowed: true},
        {name: "blocked host", allowedHosts: []string{"api.github.com"}, targetHost: "google.com", wantAllowed: false},
    }
    // ...
}

// Blocked syscalls - table-driven
func TestE2E_SeccompBlockedSyscalls(t *testing.T) {
    tsuite := []struct {
        name    string
        syscall string
        wantErr string
    }{
        {name: "mount blocked", syscall: "mount /dev/sda /mnt", wantErr: "EPERM"},
        {name: "ptrace blocked", syscall: "strace -p 1", wantErr: "EPERM"},
        {name: "reboot blocked", syscall: "reboot", wantErr: "EPERM"},
    }
    // ...
}

// Environment scrubbing - table-driven
func TestE2E_EnvironmentScrubbing(t *testing.T) {
    tsuite := []struct {
        name     string
        envVar   string
        envValue string
    }{
        {name: "github token", envVar: "GITHUB_TOKEN", envValue: "ghp_secret123"},
        {name: "aws secret", envVar: "AWS_SECRET_ACCESS_KEY", envValue: "wJalrXUtnFEMI"},
        {name: "api key", envVar: "API_KEY", envValue: "sk-proj-abc123"},
    }

    for _, tc := range tsuite {
        t.Run(tc.name, func(t *testing.T) {
            t.Setenv(tc.envVar, tc.envValue)
            exec := setupSandbox(t, DefaultConfig())
            defer exec.Close()
            stdout, _ := runCommand(t, exec, "env")
            assert.NotContains(t, stdout, tc.envValue)
        })
    }
}

// Complex tests with unique validation logic - individual functions
func TestE2E_ProcessIsolation(t *testing.T) {
    exec := setupSandbox(t, DefaultConfig())
    defer exec.Close()

    // Get PIDs visible inside sandbox
    stdout, _ := runCommand(t, exec, "ps -eo pid,comm --no-headers")
    sandboxPids := parsePids(stdout)

    // Get PIDs on host
    hostPids := getHostPids(t)

    // Verify no overlap except init
    for _, hpid := range hostPids {
        assert.NotContains(t, sandboxPids, hpid, "host PID %d visible in sandbox", hpid)
    }
}

func TestE2E_EphemeralFilesystem(t *testing.T) {
    cfg := DefaultConfig()
    cfg.Policy.Filesystem.EphemeralRoot = true

    // First sandbox - create file
    exec1 := setupSandbox(t, cfg)
    runCommand(t, exec1, "echo 'secret' > /tmp/testfile")
    exec1.Close()

    // Second sandbox - file should not exist
    exec2 := setupSandbox(t, cfg)
    defer exec2.Close()
    _, stderr := runCommand(t, exec2, "cat /tmp/testfile")
    assert.Contains(t, stderr, "No such file")
}

func TestE2E_AuditTrail(t *testing.T) {
    cfg := DefaultConfig()
    cfg.Policy.Audit.LogCommands = true

    exec := setupSandbox(t, cfg)
    defer exec.Close()

    // Run several commands
    commands := []string{"whoami", "pwd", "ls /", "echo test"}
    for _, cmd := range commands {
        runCommand(t, exec, cmd)
    }

    // Retrieve and verify audit log
    log := exec.AuditLog()
    require.Len(t, log.Entries, len(commands))
    for i, entry := range log.Entries {
        assert.Contains(t, entry.Command, commands[i])
        assert.NotZero(t, entry.Timestamp)
        assert.NotZero(t, entry.Pid)
    }
}
```

### 5. Commands to Run

```bash
# Generate protobuf
make generate

# Run all tests
make test

# Run only sandbox tests
go test -race -timeout 120s ./sandbox/...

# Run platform-specific tests
go test -race -tags=linux ./sandbox/...    # Linux only
go test -race -tags=darwin ./sandbox/...   # macOS only

# Run e2e tests (requires VM support)
go test -race -timeout 300s ./sandbox/ -run TestE2E

# Check code quality
make lint

# Generate coverage
make coverage
```

