   446→
   447→// SetPtySize sets the width and height in columns and rows of
   448→// a pseudoterminal.
   449→func (c *Client) SetPtySize(p workspaceapi.Pty, width, height int) error {
   450→	ctx, cleanup := ctxWithTimeout(c.ctx)
   451→	defer cleanup()
   452→
   453→	req := SetPtySizeRequest{
