   468→}
   469→
   470→// Watch satisfies schemeapi.Scheme.
   471→func (c *Client) Watch(
   472→	path string, ch chan<- schemeapi.EventInfo, events ...schemeapi.Event,
   473→) (int, error) {
   474→	var pbEvents []Event
   475→	for _, ev := range events {
   476→		pbEvents = append(pbEvents, Event(ev))
   477→	}
   478→	req := WatchRequest{Root: c.root, Path: path, Events: pbEvents}
   479→	stream, err := c.scheme.Watch(c.ctx, &req)
   480→	if err != nil {
   481→		return 0, err
   482→	}
   483→
   484→	msg, err := stream.Recv()
   485→	if err != nil {
   486→		return 0, fmt.Errorf("stream receive response: %w", err)
   487→	}
   488→
   489→	if msg.GetType() != WatchMessage_TypeResponse || msg.GetResponse() == nil {
   490→		return 0, errors.New("received incorrect watch message response")
   491→	}
   492→
   493→	go debug.CapturePanicReport(func() {
   494→		defer close(ch)
   495→		for {
   496→			msg, err := stream.Recv()
   497→			if err != nil {
   498→				if !errors.Is(err, io.EOF) {
   499→					c.log.Error("watch stream recv", "error", err)
   500→				}
   501→				break
   502→			}
   503→			if msg.GetType() != WatchMessage_TypeData || msg.GetData() == nil {
   504→				c.log.Error("watch stream recv data: incorrect message type")
   505→				break
   506→			}
   507→			data := msg.GetData()
   508→			uri, err := workspaceapi.ParseURI(data.GetUri())
   509→			if err != nil {
   510→				c.log.Error("could not parse URI response from server", "error", err)
   511→				break
   512→			}
   513→			var ev schemeapi.Event
   514→			switch data.GetEvent() {
   515→			case Event_Create:
   516→				ev = schemeapi.Create
   517→			case Event_Write:
   518→				ev = schemeapi.Write
   519→			case Event_Rename:
   520→				ev = schemeapi.Rename
   521→			case Event_Remove:
   522→				ev = schemeapi.Remove
   523→			}
   524→			fi := watchFileInfo{
   525→				event: ev,
   526→				uri:   uri,
   527→				isDir: data.GetIsDir(),
   528→			}
   529→			select {
   530→			case ch <- fi:
   531→			case <-c.ctx.Done():
   532→				return
   533→			}
   534→		}
   535→	})
   536→
   537→	return int(msg.GetResponse().GetId()), nil
   538→}
   539→
   540→// StopWatch satisfies schemeapi.Scheme.
   541→func (c *Client) StopWatch(id int) error {
   542→	ctx, cleanup := ctxWithTimeout(c.ctx)
   543→	defer cleanup()
   544→
   545→	req := StopWatchRequest{
   546→		Root: c.root,
   547→		Id:   int64(id),
   548→	}
   549→	_, err := c.scheme.StopWatch(ctx, &req)
   550→	return err
   551→}
   552→
   553→// Close closes all resources associated with this client.
   554→func (c *Client) Close() (ret error) {
   555→	c.cancelCtx()
   556→	return
   557→}
   558→
   559→type fileClientInfo struct {
   560→	StatResponse
   561→}
   562→
   563→func (f *fileClientInfo) Name() string {
   564→	return f.GetName()
   565→}
   566→
   567→func (f *fileClientInfo) Size() int64 {
   568→	return f.GetSize()
   569→}
   570→
   571→func (f *fileClientInfo) Mode() os.FileMode {
   572→	return os.FileMode(f.GetMode())
   573→}
   574→
   575→func (f *fileClientInfo) ModTime() time.Time {
   576→	return f.StatResponse.GetModTime().AsTime()
   577→}
   578→
   579→func (f *fileClientInfo) IsDir() bool {
   580→	return f.GetIsDir()
   581→}
   582→
   583→func (f *fileClientInfo) Sys() interface{} {
   584→	return nil
   585→}
   586→
   587→type dirEntry struct {
   588→	c        *Client
   589→	name     string
   590→	isDir    bool
   591→	modeType int32
   592→}
   593→
   594→func (e dirEntry) Name() string {
