   604→}
   605→
   606→func (e dirEntry) Info() (os.FileInfo, error) {
   607→	return e.c.Stat(e.Name())
   608→}
   609→
   610→func makeOpenRequest(root, name string, flag int, perm os.FileMode) *OpenRequest {
   611→	return &OpenRequest{
   612→		Root:     root,
   613→		Filename: name,
   614→		Mode:     int32(perm),
   615→		O_RDONLY: flag&^(os.O_APPEND|os.O_CREATE|os.O_EXCL|os.O_SYNC|os.O_TRUNC) == os.O_RDONLY,
   616→		O_WRONLY: flag&^(os.O_APPEND|os.O_CREATE|os.O_EXCL|os.O_SYNC|os.O_TRUNC) == os.O_WRONLY,
   617→		O_APPEND: flag&os.O_APPEND != 0,
   618→		O_CREATE: flag&os.O_CREATE != 0,
   619→		O_EXCL:   flag&os.O_EXCL != 0,
   620→		O_SYNC:   flag&os.O_SYNC != 0,
   621→		O_TRUNC:  flag&os.O_TRUNC != 0,
   622→	}
   623→}
   624→
   625→type errResponse interface {
   626→	GetIsExistErr() bool
   627→	GetIsNotExistErr() bool
   628→	GetIsPermissionErr() bool
   629→}
   630→
   631→func isTypedError(resp errResponse) (error, bool) {
   632→	switch {
   633→	case resp.GetIsExistErr():
   634→		return os.ErrExist, true
   635→	case resp.GetIsNotExistErr():
   636→		return os.ErrNotExist, true
   637→	case resp.GetIsPermissionErr():
   638→		return os.ErrPermission, true
   639→	default:
   640→		return nil, false
   641→	}
   642→}
