   644→func ctxWithTimeout(resourceCtx context.Context) (context.Context, func()) {
   645→	ctx, cancel := context.WithTimeout(resourceCtx, defaultTimeout)
   646→	return ctx, cancel
   647→}
   648→
   649→func tryUnwrapFile(ifc interface{}) (uint32, string) {
   650→	fc, ok := ifc.(*FileClient)
   651→	if !ok {
   652→		return 0, ""
   653→	}
   654→	return uint32(fc.Fd()), fc.Name()
   655→}
