func (p *NetworkPolicy) IsHostAllowed(host string) bool {
	if p.BlockAllEgress {
		return false
	}
	if len(p.AllowedHosts) == 0 {
		return false
	}
	for _, h := range p.AllowedHosts {
		if h == host {
