syntax = "proto3";

option go_package = "github.com/unstablebuild/rune-go-sdk/sandbox/sandboxrpc";

package sandbox;

// AgentService is the gRPC service that runs inside the guest VM.
// The host connects to this service via vsock to execute commands.
service Agent {
    // StartCommand starts a command and streams stdin/stdout/stderr.
    rpc StartCommand(stream CommandMessage) returns (stream CommandMessage);

    // Signal sends a signal to a running process.
    rpc Signal(SignalRequest) returns (SignalResponse);

    // Ping checks if the agent is alive.
    rpc Ping(PingRequest) returns (PingResponse);
}

// CommandMessage is the bidirectional streaming message for command I/O.
message CommandMessage {
    // Type indicates the message type.
    Type type = 1;

    // StartRequest is set when type is TYPE_START.
    StartRequest start = 2;

    // Started is set when type is TYPE_STARTED.
    StartedResponse started = 3;

    // IO is set when type is TYPE_IO.
    IOData io = 4;

    // Done is set when type is TYPE_DONE.
    DoneResponse done = 5;

    // Error is set when type is TYPE_ERROR.
    string error = 6;

    enum Type {
        TYPE_START = 0;
        TYPE_STARTED = 1;
        TYPE_IO = 2;
        TYPE_DONE = 3;
        TYPE_ERROR = 4;
    }
}

// StartRequest contains the command to start.
message StartRequest {
    // Path is the path to the executable.
    string path = 1;

    // Args are the command arguments (not including path).
    repeated string args = 2;

    // Dir is the working directory. If empty, uses the workspace root.
    string dir = 3;

    // Env contains environment variables in KEY=value format.
    repeated string env = 4;

    // HasStdin indicates whether stdin will be provided.
    bool has_stdin = 5;

    // HasStdout indicates whether stdout should be captured.
    bool has_stdout = 6;

    // HasStderr indicates whether stderr should be captured.
    bool has_stderr = 7;
}

// StartedResponse indicates a command has started.
message StartedResponse {
    // Pid is the process ID of the started command.
    int64 pid = 1;
}

// IOData contains stdin/stdout/stderr data.
message IOData {
    // Type indicates which stream this data is for.
    IOType type = 1;

    // Data is the actual bytes.
    bytes data = 2;

    enum IOType {
        IO_STDIN = 0;
        IO_STDOUT = 1;
        IO_STDERR = 2;
    }
}

// DoneResponse indicates a command has completed.
message DoneResponse {
    // ExitCode is the exit code of the process.
    int32 exit_code = 1;

    // ExitError contains an error message if the process failed.
    string exit_error = 2;
}

// SignalRequest sends a signal to a process.
message SignalRequest {
    // Pid is the process ID to signal.
    int64 pid = 1;

    // Signal is the signal number to send.
    int32 signal = 2;
}

// SignalResponse is the response to a signal request.
message SignalResponse {
}

// PingRequest is a health check request.
message PingRequest {
}

// PingResponse is a health check response.
message PingResponse {
    // Version is the agent version.
    string version = 1;
}

