// MockVM is a mock implementation of sandbox.VM for testing.
type MockVM struct {
	id         string
	state      sandbox.VMState
	config     *sandbox.Config
	grpcServer *grpc.Server
	listener   net.Listener
	sockPath   string
}

// ID returns the VM identifier.
func (v *MockVM) ID() string {
	return v.id
}

// State returns the VM state.
func (v *MockVM) State() sandbox.VMState {
	return v.state
}

// AgentConn returns a connection to the in-process agent server.
