func (m *MockExecutor) Signal(pid workspaceapi.Pid, _ syscall.Signal) error {
	if m.SignalErr != nil {
		return m.SignalErr
	}

	m.mu.Lock()
	defer m.mu.Unlock()

	if _, ok := m.commands[pid]; !ok {
		return syscall.ESRCH
	}
	return nil
}

// Close marks the executor as closed.
func (m *MockExecutor) Close() error {
	m.mu.Lock()
	defer m.mu.Unlock()

	m.closed = true
	return m.CloseErr
}

