func (m *MockExecutor) Commands() map[workspaceapi.Pid]workspaceapi.Cmd {
	m.mu.Lock()
	defer m.mu.Unlock()

	result := make(map[workspaceapi.Pid]workspaceapi.Cmd, len(m.commands))
	for k, v := range m.commands {
		result[k] = v
	}
	return result
}

// IsClosed returns whether the executor has been closed.
func (m *MockExecutor) IsClosed() bool {
	m.mu.Lock()
	defer m.mu.Unlock()
	return m.closed
}

