	"google.golang.org/grpc"
	"google.golang.org/grpc/credentials/insecure"
)

func setupClientServer(t *testing.T) (*Client, func()) {
	t.Helper()

	// Use /tmp to keep the socket path short (macOS has 104 byte limit)
	sockPath := fmt.Sprintf("/tmp/sbtest-%d.sock", time.Now().UnixNano())
	lis, err := net.Listen("unix", sockPath)
	require.NoError(t, err)

	// Start server
	grpcServer := grpc.NewServer()
	RegisterAgentServer(grpcServer, NewServer())

	go func() {
		_ = grpcServer.Serve(lis)
	}()

	// Connect client
	ctx := context.Background()
	conn, err := grpc.NewClient(
		"unix://"+sockPath,
		grpc.WithTransportCredentials(insecure.NewCredentials()),
	)
	require.NoError(t, err)

	client := NewClient(ctx, conn)

	cleanup := func() {
		_ = client.Close()
		_ = conn.Close()
		grpcServer.Stop()
		_ = lis.Close()
		_ = os.Remove(sockPath)
	}

	return client, cleanup
}

func TestClientServer_Ping(t *testing.T) {
	client, cleanup := setupClientServer(t)
	defer cleanup()

	err := client.Ping(context.Background())
	require.NoError(t, err)
}

func TestClientServer_StartCommand(t *testing.T) {
	client, cleanup := setupClientServer(t)
	defer cleanup()

	tsuite := []struct {
		name       string
		cmd        workspaceapi.Cmd
		wantStdout string
		wantErr    bool
	}{
		{
			name: "simple echo",
			cmd: workspaceapi.Cmd{
				Path: "/bin/echo",
				Args: []string{"hello", "world"},
			},
			wantStdout: "hello world\n",
		},
		{
			name: "with env",
			cmd: workspaceapi.Cmd{
				Path: "/bin/sh",
				Args: []string{"-c", "echo $TEST_VAR"},
				Env:  []string{"TEST_VAR=test_value"},
			},
			wantStdout: "test_value\n",
		},
		{
			name: "with working dir",
			cmd: workspaceapi.Cmd{
				Path: "/bin/pwd",
				Dir:  os.TempDir(),
			},
			// Use os.TempDir() which resolves symlinks on macOS
			wantStdout: os.TempDir() + "\n",
		},
		{
			name: "nonexistent command",
			cmd: workspaceapi.Cmd{
				Path: "/nonexistent/command",
			},
			wantErr: true,
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			stdout := &bytes.Buffer{}
			stderr := &bytes.Buffer{}
			watchCh := make(chan error, 1)

			tc.cmd.Stdout = stdout
			tc.cmd.Stderr = stderr
			tc.cmd.Watcher = &testWatcher{ch: watchCh}

			ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
			defer cancel()

			pid, err := client.StartCommand(ctx, tc.cmd)
			if tc.wantErr {
				// For nonexistent commands, the error may come from StartCommand
				// or from the watcher
				if err == nil {
					select {
					case werr := <-watchCh:
						require.Error(t, werr)
					case <-ctx.Done():
						t.Fatal("timeout waiting for watcher")
					}
				}
				return
			}

			require.NoError(t, err)
			assert.NotZero(t, pid)

			// Wait for command to complete
			select {
			case werr := <-watchCh:
				require.NoError(t, werr)
			case <-ctx.Done():
				t.Fatal("timeout waiting for command")
			}

			if tc.wantStdout != "" {
				assert.Equal(t, tc.wantStdout, stdout.String())
			}
		})
	}
}

