func TestClientServer_Signal(t *testing.T) {
	client, cleanup := setupClientServer(t)
	defer cleanup()

	// Start a long-running process
	stdout := &bytes.Buffer{}
	watchCh := make(chan error, 1)

	cmd := workspaceapi.Cmd{
		Path:    "/bin/sleep",
		Args:    []string{"60"},
		Stdout:  stdout,
		Watcher: &testWatcher{ch: watchCh},
	}

	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	pid, err := client.StartCommand(ctx, cmd)
	require.NoError(t, err)
	assert.NotZero(t, pid)

	// Give it time to start
	time.Sleep(100 * time.Millisecond)

	// Send SIGTERM
	err = client.Signal(pid, syscall.SIGTERM)
	require.NoError(t, err)

	// Wait for process to terminate
