func TestClientServer_ConcurrentCommands(t *testing.T) {
	client, cleanup := setupClientServer(t)
	defer cleanup()

	const numCommands = 5
	results := make(chan string, numCommands)
	errors := make(chan error, numCommands)

	for i := 0; i < numCommands; i++ {
		go func(idx int) {
			stdout := &bytes.Buffer{}
			watchCh := make(chan error, 1)

			cmd := workspaceapi.Cmd{
				Path:    "/bin/echo",
				Args:    []string{"-n", string(rune('A' + idx))},
				Stdout:  stdout,
				Watcher: &testWatcher{ch: watchCh},
			}

			ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
			defer cancel()

			_, err := client.StartCommand(ctx, cmd)
			if err != nil {
				errors <- err
				return
			}

			select {
			case werr := <-watchCh:
				if werr != nil {
					errors <- werr
					return
				}
			case <-ctx.Done():
				errors <- ctx.Err()
				return
			}

			results <- stdout.String()
		}(i)
	}

	// Collect all results
	var outputs []string
	for i := 0; i < numCommands; i++ {
		select {
		case r := <-results:
			outputs = append(outputs, r)
		case err := <-errors:
			t.Fatalf("command failed: %v", err)
		case <-time.After(30 * time.Second):
			t.Fatal("timeout waiting for commands")
		}
	}

	// Verify we got all expected outputs
	assert.Len(t, outputs, numCommands)
	for _, o := range outputs {
		assert.Len(t, o, 1)
		assert.True(t, o[0] >= 'A' && o[0] < 'A'+numCommands)
	}
}

