// Skip tests if we don't have the required binaries
func TestMain(m *testing.M) {
	// Check for required binaries
	required := []string{"/bin/echo", "/bin/cat", "/bin/sh", "/bin/pwd", "/bin/sleep"}
	for _, bin := range required {
		if _, err := os.Stat(bin); os.IsNotExist(err) {
			os.Exit(0) // Skip tests if binaries don't exist
		}
	}
	os.Exit(m.Run())
}

