// realTempDir returns the real path to the temp directory, resolving symlinks.
// On macOS, /tmp is a symlink to /private/tmp.
func realTempDir() string {
	path, err := filepath.EvalSymlinks(os.TempDir())
	if err != nil {
		return os.TempDir()
	}
	return path
}

