// Package sandboxtest provides test utilities for the sandbox package.
package sandboxtest

import (
	"context"
	"maps"
	"sync"
	"sync/atomic"
	"syscall"

	"github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
)

// MockExecutor is a mock implementation of workspaceapi.Executor for testing.
// It records all commands and signals for later inspection.
type MockExecutor struct {
	mu         sync.Mutex
	pidCounter atomic.Int64
	commands   map[workspaceapi.Pid]workspaceapi.Cmd
	signals    map[workspaceapi.Pid][]syscall.Signal
	closed     bool

	// StartErr is the error to return from Start.
	StartErr error

	// SignalErr is the error to return from Signal.
	SignalErr error

	// CloseErr is the error to return from Close.
	CloseErr error
}

// NewMockExecutor creates a new mock executor.
func NewMockExecutor() *MockExecutor {
	return &MockExecutor{
		commands: make(map[workspaceapi.Pid]workspaceapi.Cmd),
		signals:  make(map[workspaceapi.Pid][]syscall.Signal),
	}
}

// Start records the command and returns a mock PID.
func (m *MockExecutor) Start(
	_ context.Context, cmd workspaceapi.Cmd,
) (workspaceapi.Pid, error) {
	if m.StartErr != nil {
		return 0, m.StartErr
	}

	m.mu.Lock()
	defer m.mu.Unlock()

	pid := workspaceapi.Pid(m.pidCounter.Add(1))
	m.commands[pid] = cmd

	// Notify watcher immediately with no error
	if cmd.Watcher != nil && cmd.Watcher.WatchProcess() != nil {
		go func() {
			cmd.Watcher.WatchProcess() <- nil
		}()
	}

	return pid, nil
}

// Signal records the signal request.
func (m *MockExecutor) Signal(pid workspaceapi.Pid, sig syscall.Signal) error {
	if m.SignalErr != nil {
		return m.SignalErr
	}

	m.mu.Lock()
	defer m.mu.Unlock()

	if _, ok := m.commands[pid]; !ok {
		return syscall.ESRCH
	}
	m.signals[pid] = append(m.signals[pid], sig)
	return nil
}

// Close marks the executor as closed.
func (m *MockExecutor) Close() error {
	m.mu.Lock()
	defer m.mu.Unlock()

	m.closed = true
	return m.CloseErr
}

// Commands returns all commands that were started.
func (m *MockExecutor) Commands() map[workspaceapi.Pid]workspaceapi.Cmd {
	m.mu.Lock()
	defer m.mu.Unlock()

	result := make(map[workspaceapi.Pid]workspaceapi.Cmd, len(m.commands))
	maps.Copy(result, m.commands)
	return result
}

// Signals returns all signals sent to a process.
func (m *MockExecutor) Signals(pid workspaceapi.Pid) []syscall.Signal {
	m.mu.Lock()
	defer m.mu.Unlock()

	return append([]syscall.Signal{}, m.signals[pid]...)
}

// IsClosed returns whether the executor has been closed.
func (m *MockExecutor) IsClosed() bool {
	m.mu.Lock()
	defer m.mu.Unlock()
	return m.closed
}

