func NewServer() *Server {
	return &Server{
		log: slog.Default().With("struct", "sandboxrpc.Server"),
	}
}

// StartCommand handles bidirectional streaming for command execution.
func (s *Server) StartCommand(stream Agent_StartCommandServer) error {
	// Receive start request
	msg, err := stream.Recv()
	if err != nil {
		return fmt.Errorf("recv start request: %w", err)
	}

	if msg.GetType() != CommandMessage_TYPE_START || msg.GetStart() == nil {
		return fmt.Errorf("expected start request, got %v", msg.GetType())
	}

	req := msg.GetStart()
	s.log.Debug("starting command", "path", req.GetPath(), "args", req.GetArgs())

	// Create the command
	cmd := exec.Command(req.GetPath(), req.GetArgs()...)
	cmd.Dir = req.GetDir()
	cmd.Env = req.GetEnv()
	if len(cmd.Env) == 0 {
		cmd.Env = os.Environ()
	}

	// Set up pipes
	var stdin io.WriteCloser
	var stdout, stderr io.ReadCloser

	if req.GetHasStdin() {
		stdin, err = cmd.StdinPipe()
		if err != nil {
			return fmt.Errorf("stdin pipe: %w", err)
		}
	}

	if req.GetHasStdout() {
		stdout, err = cmd.StdoutPipe()
		if err != nil {
			return fmt.Errorf("stdout pipe: %w", err)
		}
	}

	if req.GetHasStderr() {
		stderr, err = cmd.StderrPipe()
		if err != nil {
			return fmt.Errorf("stderr pipe: %w", err)
		}
	}

	// Start the command
	if err := cmd.Start(); err != nil {
		return fmt.Errorf("start command: %w", err)
	}

	pid := int64(cmd.Process.Pid)
	s.processes.Store(pid, cmd.Process)
	defer s.processes.Delete(pid)

	// Send started response
	err = stream.Send(&CommandMessage{
		Type:    CommandMessage_TYPE_STARTED,
		Started: &StartedResponse{Pid: pid},
	})
	if err != nil {
		_ = cmd.Process.Kill()
		return fmt.Errorf("send started: %w", err)
	}

	s.log.Debug("command started", "pid", pid)

	// Stream I/O
	var wg sync.WaitGroup
	errCh := make(chan error, 3)

	// Stream stdin from client to process
	if stdin != nil {
		wg.Add(1)
		go func() {
			defer wg.Done()
			defer stdin.Close()
			if err := s.streamStdin(stream, stdin); err != nil {
				errCh <- err
			}
		}()
	}

	// Stream stdout from process to client
	if stdout != nil {
		wg.Add(1)
		go func() {
			defer wg.Done()
			if err := s.streamOutput(stream, stdout, IOData_IO_STDOUT); err != nil {
				errCh <- err
			}
		}()
	}

	// Stream stderr from process to client
	if stderr != nil {
		wg.Add(1)
		go func() {
			defer wg.Done()
			if err := s.streamOutput(stream, stderr, IOData_IO_STDERR); err != nil {
				errCh <- err
			}
		}()
	}

	// Wait for I/O to complete
	wg.Wait()
	close(errCh)

	// Wait for the command to finish
	waitErr := cmd.Wait()

	// Send done response
	done := &DoneResponse{}
	if waitErr != nil {
		done.ExitError = waitErr.Error()
		var exitErr *exec.ExitError
		if errors.As(waitErr, &exitErr) {
			done.ExitCode = int32(exitErr.ExitCode())
		}
	}

	err = stream.Send(&CommandMessage{
		Type: CommandMessage_TYPE_DONE,
		Done: done,
	})
	if err != nil {
		return fmt.Errorf("send done: %w", err)
	}

	s.log.Debug("command completed", "pid", pid, "error", waitErr)
	return nil
}

func (s *Server) streamStdin(stream Agent_StartCommandServer, stdin io.WriteCloser) error {
	for {
		msg, err := stream.Recv()
		if err != nil {
			if err == io.EOF {
				return nil
			}
			return err
		}

		if msg.GetType() != CommandMessage_TYPE_IO {
			continue
		}

		io := msg.GetIo()
		if io == nil || io.GetType() != IOData_IO_STDIN {
			continue
		}

		_, err = stdin.Write(io.GetData())
		if err != nil {
			return err
		}
	}
}

func (s *Server) streamOutput(
	stream Agent_StartCommandServer,
	r io.Reader,
	ioType IOData_IOType,
) error {
	buf := make([]byte, 64*1024)
	for {
		n, err := r.Read(buf)
		if err != nil {
			if err == io.EOF {
				return nil
			}
			return err
		}

		if n > 0 {
			msg := &CommandMessage{
				Type: CommandMessage_TYPE_IO,
				Io: &IOData{
					Type: ioType,
					Data: buf[:n],
				},
			}
			if err := stream.Send(msg); err != nil {
				return err
			}
		}
	}
}

// Signal sends a signal to a running process.
func (s *Server) Signal(
	_ context.Context, req *SignalRequest,
) (*SignalResponse, error) {
	v, ok := s.processes.Load(req.GetPid())
	if !ok {
		return nil, fmt.Errorf("process %d not found", req.GetPid())
	}

	proc := v.(*os.Process)
	sig := syscall.Signal(req.GetSignal())

	if err := proc.Signal(sig); err != nil {
		return nil, fmt.Errorf("signal process: %w", err)
	}

	return &SignalResponse{}, nil
}

// Ping checks if the agent is alive.
func (s *Server) Ping(_ context.Context, _ *PingRequest) (*PingResponse, error) {
	return &PingResponse{Version: Version}, nil
}

