   121→// Close closes the sandbox and cleans up resources.
   122→// The VM state directory is preserved so it appears in "matchlock list".
   123→// Call Remove after Close to delete the state entirely.
   124→//
   125→// timeout controls how long to wait for the process to exit after sending the
   126→// close request. A zero value kills the process immediately. When a non-zero
   127→// timeout expires, the process is forcefully killed.
   128→func (c *Client) Close(timeout time.Duration) error {
   129→	c.mu.Lock()
   130→	if c.closed {
   131→		c.mu.Unlock()
   132→		return nil
   133→	}
   134→	c.closed = true
   135→	c.mu.Unlock()
   136→
   137→	params := map[string]interface{}{
   138→		"timeout_seconds": timeout.Seconds(),
   139→	}
   140→	c.sendRequest("close", params)
   141→	c.stdin.Close()
   142→
   143→	done := make(chan error, 1)
   144→	go func() { done <- c.cmd.Wait() }()
   145→
   146→	select {
   147→	case err := <-done:
   148→		return err
   149→	case <-time.After(timeout):
   150→		c.cmd.Process.Kill()
   151→		<-done
   152→		return fmt.Errorf("close timed out after %s, process killed", timeout)
   153→	}
   154→}
