   148→	}
   149→
   150→	result := *c
   151→	if other.Image != "" {
   152→		result.Image = other.Image
   153→	}
   154→	if other.Resources != nil {
   155→		if result.Resources == nil {
   156→			result.Resources = &Resources{}
   157→		}
   158→		if other.Resources.CPUs > 0 {
   159→			result.Resources.CPUs = other.Resources.CPUs
   160→		}
   161→		if other.Resources.MemoryMB > 0 {
   162→			result.Resources.MemoryMB = other.Resources.MemoryMB
   163→		}
   164→		if other.Resources.DiskSizeMB > 0 {
   165→			result.Resources.DiskSizeMB = other.Resources.DiskSizeMB
   166→		}
   167→		if other.Resources.TimeoutSeconds > 0 {
   168→			result.Resources.TimeoutSeconds = other.Resources.TimeoutSeconds
   169→		}
   170→	}
   171→	if other.Network != nil {
   172→		result.Network = other.Network
   173→	}
   174→	if other.VFS != nil {
   175→		result.VFS = other.VFS
   176→	}
   177→	if other.Privileged {
   178→		result.Privileged = true
   179→	}
   180→	if other.Env != nil {
   181→		result.Env = other.Env
   182→	}
   183→	if len(other.ExtraDisks) > 0 {
   184→		result.ExtraDisks = other.ExtraDisks
   185→	}
   186→	if other.ImageCfg != nil {
   187→		result.ImageCfg = other.ImageCfg
   188→	}
   189→	return &result
   190→}
