   192→// ComposeCommand builds a shell command from image ENTRYPOINT/CMD and user-provided args.
   193→// Follows Docker semantics: if user provides args, they replace CMD; ENTRYPOINT is always prepended.
   194→func (ic *ImageConfig) ComposeCommand(userArgs []string) []string {
   195→	if ic == nil {
   196→		return userArgs
   197→	}
   198→	result := make([]string, len(ic.Entrypoint))
   199→	copy(result, ic.Entrypoint)
   200→	if len(userArgs) > 0 {
   201→		return append(result, userArgs...)
   202→	}
   203→	result = append(result, ic.Cmd...)
   204→	if len(result) == 0 {
   205→		return nil
   206→	}
   207→	return result
   208→}
