    20→func NewMountRouter(mounts map[string]Provider) *MountRouter {
    21→	r := &MountRouter{}
    22→	for path, provider := range mounts {
    23→		r.mounts = append(r.mounts, mount{path: filepath.Clean(path), provider: provider})
    24→	}
    25→	sort.Slice(r.mounts, func(i, j int) bool {
    26→		return len(r.mounts[i].path) > len(r.mounts[j].path)
