    33→func (r *MountRouter) resolve(path string) (Provider, string, error) {
    34→	path = filepath.Clean(path)
    35→	for _, m := range r.mounts {
    36→		if path == m.path || strings.HasPrefix(path, m.path+"/") {
    37→			rel := strings.TrimPrefix(path, m.path)
    38→			if rel == "" {
    39→				rel = "/"
    40→			}
    41→			return m.provider, rel, nil
    42→		}
    43→	}
    44→	return nil, "", syscall.ENOENT
    45→}
