     8→// JSON-RPC request/response types
     9→type request struct {
    10→	JSONRPC string      `json:"jsonrpc"`
    11→	Method  string      `json:"method"`
    12→	Params  interface{} `json:"params,omitempty"`
    13→	ID      uint64      `json:"id"`
    14→}
    15→
    16→type response struct {
    17→	JSONRPC string          `json:"jsonrpc"`
    18→	Result  json.RawMessage `json:"result,omitempty"`
    19→	Error   *rpcError       `json:"error,omitempty"`
    20→	ID      *uint64         `json:"id,omitempty"`
    21→}
    22→
    23→// notification is a JSON-RPC notification (no ID) with a method and params
    24→type notification struct {
    25→	Method string          `json:"method"`
    26→	Params json.RawMessage `json:"params"`
    27→}
    28→
    29→type rpcError struct {
    30→	Code    int    `json:"code"`
    31→	Message string `json:"message"`
    32→}
    33→
    34→// Error codes
    35→const (
    36→	ErrCodeParse          = -32700
    37→	ErrCodeInvalidRequest = -32600
    38→	ErrCodeMethodNotFound = -32601
    39→	ErrCodeInvalidParams  = -32602
    40→	ErrCodeInternal       = -32603
    41→	ErrCodeVMFailed       = -32000
    42→	ErrCodeExecFailed     = -32001
    43→	ErrCodeFileFailed     = -32002
    44→)
    45→
    46→// RPCError represents an error from the Matchlock RPC
    47→type RPCError struct {
    48→	Code    int
    49→	Message string
    50→}
    51→
    52→func (e *RPCError) Error() string {
    53→	return fmt.Sprintf("matchlock RPC error [%d]: %s", e.Code, e.Message)
    54→}
    55→
    56→// IsVMError returns true if the error is a VM-related error
    57→func (e *RPCError) IsVMError() bool {
    58→	return e.Code == ErrCodeVMFailed
    59→}
    60→
    61→// IsExecError returns true if the error is an execution error
    62→func (e *RPCError) IsExecError() bool {
    63→	return e.Code == ErrCodeExecFailed
    64→}
    65→
    66→// IsFileError returns true if the error is a file operation error
    67→func (e *RPCError) IsFileError() bool {
    68→	return e.Code == ErrCodeFileFailed
    69→}
    70→
    71→// pendingRequest tracks an in-flight request awaiting its response.
    72→type pendingRequest struct {
    73→	ch chan pendingResult
    74→	// onNotification is called for streaming notifications matching this request ID.
    75→	// It is only set for exec_stream requests.
    76→	onNotification func(method string, params json.RawMessage)
    77→}
    78→
    79→type pendingResult struct {
    80→	result json.RawMessage
    81→	err    error
    82→}
    83→
    84→// sendRequest sends a JSON-RPC request and returns the result.
    85→// It is safe for concurrent use.
    86→func (c *Client) sendRequest(method string, params interface{}) (json.RawMessage, error) {
    87→	return c.sendRequestWithNotify(method, params, nil)
    88→}
    89→
    90→// sendRequestWithNotify sends a JSON-RPC request and returns the result.
    91→// If onNotification is non-nil, it is called for each streaming notification
    92→// matching this request's ID before the final response arrives.
    93→func (c *Client) sendRequestWithNotify(method string, params interface{}, onNotification func(string, json.RawMessage)) (json.RawMessage, error) {
    94→	c.readerOnce.Do(c.startReader)
    95→
    96→	id := c.requestID.Add(1)
    97→
    98→	pending := &pendingRequest{
    99→		ch:             make(chan pendingResult, 1),
   100→		onNotification: onNotification,
   101→	}
   102→
   103→	c.pendingMu.Lock()
   104→	if c.pending == nil {
   105→		c.pendingMu.Unlock()
   106→		return nil, fmt.Errorf("client is closed")
   107→	}
   108→	c.pending[id] = pending
   109→	c.pendingMu.Unlock()
   110→
   111→	defer func() {
   112→		c.pendingMu.Lock()
   113→		delete(c.pending, id)
   114→		c.pendingMu.Unlock()
   115→	}()
   116→
   117→	req := request{
   118→		JSONRPC: "2.0",
   119→		Method:  method,
   120→		Params:  params,
   121→		ID:      id,
   122→	}
   123→
   124→	data, err := json.Marshal(req)
   125→	if err != nil {
   126→		return nil, fmt.Errorf("failed to marshal request: %w", err)
   127→	}
   128→
   129→	c.writeMu.Lock()
   130→	_, writeErr := fmt.Fprintln(c.stdin, string(data))
   131→	c.writeMu.Unlock()
   132→	if writeErr != nil {
   133→		return nil, fmt.Errorf("failed to write request: %w", writeErr)
   134→	}
   135→
   136→	result := <-pending.ch
   137→	return result.result, result.err
   138→}
   139→
   140→// startReader launches the background goroutine that reads JSON-RPC responses
   141→// from stdout and dispatches them to the appropriate pending request.
   142→func (c *Client) startReader() {
   143→	go func() {
   144→		for {
   145→			line, err := c.stdout.ReadBytes('\n')
   146→			if err != nil {
   147→				c.pendingMu.Lock()
   148→				for _, p := range c.pending {
   149→					p.ch <- pendingResult{err: fmt.Errorf("connection closed: %w", err)}
   150→				}
   151→				c.pending = nil
   152→				c.pendingMu.Unlock()
   153→				return
   154→			}
   155→
   156→			var resp response
   157→			if err := json.Unmarshal(line, &resp); err != nil {
   158→				continue
   159→			}
   160→
   161→			// Notification (no ID) — may be a stream chunk or an event
   162→			if resp.ID == nil {
   163→				var notif notification
   164→				if err := json.Unmarshal(line, &notif); err != nil {
   165→					continue
   166→				}
   167→				c.handleNotification(notif)
   168→				continue
   169→			}
   170→
   171→			c.pendingMu.Lock()
   172→			p, ok := c.pending[*resp.ID]
   173→			c.pendingMu.Unlock()
   174→
   175→			if !ok {
   176→				continue
   177→			}
   178→
   179→			if resp.Error != nil {
   180→				p.ch <- pendingResult{err: &RPCError{
   181→					Code:    resp.Error.Code,
   182→					Message: resp.Error.Message,
   183→				}}
   184→			} else {
   185→				p.ch <- pendingResult{result: resp.Result}
   186→			}
   187→		}
   188→	}()
   189→}
   190→
   191→// handleNotification routes JSON-RPC notifications. Stream notifications
   192→// (exec_stream.stdout, exec_stream.stderr) include a request ID in params
   193→// and are forwarded to the matching pending request's callback.
   194→func (c *Client) handleNotification(notif notification) {
   195→	switch notif.Method {
   196→	case "exec_stream.stdout", "exec_stream.stderr":
   197→		var p struct {
   198→			ID *uint64 `json:"id"`
   199→		}
   200→		if err := json.Unmarshal(notif.Params, &p); err != nil || p.ID == nil {
   201→			return
   202→		}
   203→		c.pendingMu.Lock()
   204→		pending, ok := c.pending[*p.ID]
   205→		c.pendingMu.Unlock()
   206→		if ok && pending.onNotification != nil {
   207→			pending.onNotification(notif.Method, notif.Params)
   208→		}
   209→	}
   210→}
