    15→func prepareExecEnv(config *api.Config, caPool *sandboxnet.CAPool, pol *policy.Engine) *api.ExecOptions {
    16→	opts := &api.ExecOptions{
    17→		WorkingDir: config.GetWorkspace(),
    18→		Env:        make(map[string]string),
    19→	}
    20→
    21→	if ic := config.ImageCfg; ic != nil {
    22→		for k, v := range ic.Env {
    23→			opts.Env[k] = v
    24→		}
    25→		if ic.WorkingDir != "" {
    26→			opts.WorkingDir = ic.WorkingDir
    27→		}
    28→		if ic.User != "" {
    29→			opts.User = ic.User
    30→		}
    31→	}
    32→
    33→	if caPool != nil {
    34→		certPath := "/etc/ssl/certs/matchlock-ca.crt"
    35→		opts.Env["SSL_CERT_FILE"] = certPath
    36→		opts.Env["REQUESTS_CA_BUNDLE"] = certPath
    37→		opts.Env["CURL_CA_BUNDLE"] = certPath
    38→		opts.Env["NODE_EXTRA_CA_CERTS"] = certPath
    39→	}
    40→	if pol != nil {
    41→		for name, placeholder := range pol.GetPlaceholders() {
    42→			opts.Env[name] = placeholder
    43→		}
    44→	}
    45→	return opts
    46→}
    47→
    48→func execCommand(ctx context.Context, machine vm.Machine, config *api.Config, caPool *sandboxnet.CAPool, pol *policy.Engine, command string, opts *api.ExecOptions) (*api.ExecResult, error) {
    49→	if opts == nil {
    50→		opts = &api.ExecOptions{}
    51→	}
    52→	if opts.Env == nil {
    53→		opts.Env = make(map[string]string)
    54→	}
    55→
    56→	prepared := prepareExecEnv(config, caPool, pol)
    57→	if opts.WorkingDir == "" {
    58→		opts.WorkingDir = prepared.WorkingDir
    59→	}
    60→	if opts.User == "" {
    61→		opts.User = prepared.User
    62→	}
    63→	for k, v := range prepared.Env {
    64→		opts.Env[k] = v
    65→	}
    66→
    67→	return machine.Exec(ctx, command, opts)
    68→}
