    70→func writeFile(vfsRoot *vfs.MountRouter, path string, content []byte, mode uint32) error {
    71→	if mode == 0 {
    72→		mode = 0644
    73→	}
    74→	h, err := vfsRoot.Create(path, os.FileMode(mode))
    75→	if err != nil {
    76→		return err
    77→	}
    78→	defer h.Close()
    79→	_, err = h.Write(content)
    80→	return err
    81→}
