    83→func readFile(vfsRoot *vfs.MountRouter, path string) ([]byte, error) {
    84→	h, err := vfsRoot.Open(path, os.O_RDONLY, 0)
    85→	if err != nil {
    86→		return nil, err
    87→	}
    88→	defer h.Close()
    89→
