    20→	"golang.org/x/sys/unix"
    21→)
    22→
    23→// FirewallRules is an interface for managing firewall rules.
    24→type FirewallRules interface {
    25→	Setup() error
    26→	Cleanup() error
    27→}
    28→
    29→// Sandbox represents a running sandbox VM with all associated resources.
    30→type Sandbox struct {
    31→	id          string
    32→	config      *api.Config
    33→	machine     vm.Machine
    34→	proxy       *sandboxnet.TransparentProxy
    35→	fwRules     FirewallRules
    36→	natRules    *sandboxnet.NFTablesNAT
    37→	policy      *policy.Engine
    38→	vfsRoot     *vfs.MountRouter
    39→	vfsServer   *vfs.VFSServer
    40→	vfsStopFunc func()
    41→	events      chan api.Event
    42→	stateMgr    *state.Manager
    43→	tapName     string
    44→	caPool      *sandboxnet.CAPool
    45→	subnetInfo  *state.SubnetInfo
    46→	subnetAlloc *state.SubnetAllocator
    47→	workspace   string
    48→	rootfsPath  string
    49→}
    50→
    51→// Options configures sandbox creation.
    52→type Options struct {
    53→	// KernelPath overrides the default kernel path
    54→	KernelPath string
    55→	// RootfsPath is the path to the rootfs image (required)
    56→	RootfsPath string
    57→}
    58→
    59→// New creates a new sandbox VM with the given configuration.
    60→func New(ctx context.Context, config *api.Config, opts *Options) (*Sandbox, error) {
    61→	if opts == nil {
    62→		opts = &Options{}
    63→	}
    64→	if opts.RootfsPath == "" {
    65→		return nil, fmt.Errorf("RootfsPath is required")
    66→	}
    67→
    68→	id := "vm-" + uuid.New().String()[:8]
    69→	workspace := config.GetWorkspace()
    70→
    71→	stateMgr := state.NewManager()
    72→	if err := stateMgr.Register(id, config); err != nil {
    73→		return nil, fmt.Errorf("failed to register VM state: %w", err)
    74→	}
    75→
    76→	// Create a copy of the rootfs for this VM (copy-on-write if supported)
    77→	vmRootfsPath := stateMgr.Dir(id) + "/rootfs.ext4"
    78→	if err := copyRootfs(opts.RootfsPath, vmRootfsPath); err != nil {
    79→		stateMgr.Unregister(id)
    80→		return nil, fmt.Errorf("failed to copy rootfs: %w", err)
    81→	}
    82→
    83→	// Inject matchlock components (guest-agent, guest-fused, init, DNS) and resize
    84→	var diskSizeMB int64
    85→	if config.Resources != nil {
    86→		diskSizeMB = int64(config.Resources.DiskSizeMB)
    87→	}
    88→	if err := prepareRootfs(vmRootfsPath, diskSizeMB); err != nil {
    89→		os.Remove(vmRootfsPath)
    90→		stateMgr.Unregister(id)
    91→		return nil, fmt.Errorf("failed to prepare rootfs: %w", err)
    92→	}
    93→
    94→	// Create CAPool early and inject cert into rootfs before VM creation
    95→	needsProxy := config.Network != nil && (len(config.Network.AllowedHosts) > 0 || len(config.Network.Secrets) > 0)
    96→	var caPool *sandboxnet.CAPool
    97→	if needsProxy {
    98→		var err error
    99→		caPool, err = sandboxnet.NewCAPool()
   100→		if err != nil {
   101→			os.Remove(vmRootfsPath)
   102→			stateMgr.Unregister(id)
   103→			return nil, fmt.Errorf("failed to create CA pool: %w", err)
   104→		}
   105→		if err := injectConfigFileIntoRootfs(vmRootfsPath, "/etc/ssl/certs/matchlock-ca.crt", caPool.CACertPEM()); err != nil {
   106→			os.Remove(vmRootfsPath)
   107→			stateMgr.Unregister(id)
   108→			return nil, fmt.Errorf("failed to inject CA cert into rootfs: %w", err)
   109→		}
   110→	}
   111→
   112→	// Allocate unique subnet for this VM
   113→	subnetAlloc := state.NewSubnetAllocator()
   114→	subnetInfo, err := subnetAlloc.Allocate(id)
   115→	if err != nil {
   116→		os.Remove(vmRootfsPath)
   117→		stateMgr.Unregister(id)
   118→		return nil, fmt.Errorf("failed to allocate subnet: %w", err)
   119→	}
   120→
   121→	backend := linux.NewLinuxBackend()
   122→
   123→	kernelPath := opts.KernelPath
   124→	if kernelPath == "" {
   125→		kernelPath = DefaultKernelPath()
   126→	}
   127→
   128→	var extraDisks []vm.DiskConfig
   129→	for _, d := range config.ExtraDisks {
   130→		if err := api.ValidateGuestMount(d.GuestMount); err != nil {
   131→			subnetAlloc.Release(id)
   132→			stateMgr.Unregister(id)
   133→			return nil, fmt.Errorf("invalid extra disk config: %w", err)
   134→		}
   135→		extraDisks = append(extraDisks, vm.DiskConfig{
   136→			HostPath:   d.HostPath,
   137→			GuestMount: d.GuestMount,
   138→			ReadOnly:   d.ReadOnly,
   139→		})
   140→	}
   141→
   142→	vmConfig := &vm.VMConfig{
   143→		ID:         id,
   144→		KernelPath: kernelPath,
   145→		RootfsPath: vmRootfsPath,
   146→		CPUs:       config.Resources.CPUs,
   147→		MemoryMB:   config.Resources.MemoryMB,
   148→		SocketPath: stateMgr.SocketPath(id) + ".sock",
   149→		LogPath:    stateMgr.LogPath(id),
   150→		VsockCID:   3,
   151→		VsockPath:  stateMgr.Dir(id) + "/vsock.sock",
   152→		GatewayIP:  subnetInfo.GatewayIP,
   153→		GuestIP:    subnetInfo.GuestIP,
   154→		SubnetCIDR: subnetInfo.GatewayIP + "/24",
   155→		Workspace:  workspace,
   156→		Privileged: config.Privileged,
   157→		ExtraDisks: extraDisks,
   158→		DNSServers: config.Network.GetDNSServers(),
   159→	}
   160→
   161→	machine, err := backend.Create(ctx, vmConfig)
   162→	if err != nil {
   163→		subnetAlloc.Release(id)
   164→		stateMgr.Unregister(id)
   165→		return nil, fmt.Errorf("failed to create VM: %w", err)
   166→	}
   167→
   168→	linuxMachine := machine.(*linux.LinuxMachine)
   169→
   170→	// Auto-add secret hosts to allowed hosts if secrets are defined
   171→	if config.Network != nil && len(config.Network.Secrets) > 0 {
   172→		hostSet := make(map[string]bool)
   173→		for _, h := range config.Network.AllowedHosts {
   174→			hostSet[h] = true
   175→		}
   176→		for _, secret := range config.Network.Secrets {
   177→			for _, h := range secret.Hosts {
   178→				if !hostSet[h] {
   179→					config.Network.AllowedHosts = append(config.Network.AllowedHosts, h)
   180→					hostSet[h] = true
   181→				}
   182→			}
   183→		}
   184→	}
   185→
   186→	// Create policy engine
   187→	policyEngine := policy.NewEngine(config.Network)
   188→
   189→	// Create event channel
   190→	events := make(chan api.Event, 100)
   191→
   192→	// Set up transparent proxy for HTTP/HTTPS interception
   193→	gatewayIP := subnetInfo.GatewayIP
   194→	const proxyBindAddr = "0.0.0.0"
   195→
   196→	var proxy *sandboxnet.TransparentProxy
   197→	var fwRules FirewallRules
   198→
   199→	if needsProxy {
   200→		proxy, err = sandboxnet.NewTransparentProxy(&sandboxnet.ProxyConfig{
   201→			BindAddr:        proxyBindAddr,
   202→			HTTPPort:        0,
   203→			HTTPSPort:       0,
   204→			PassthroughPort: 0,
   205→			Policy:          policyEngine,
   206→			Events:          events,
   207→			CAPool:          caPool,
   208→		})
   209→		if err != nil {
   210→			machine.Close(ctx)
   211→			subnetAlloc.Release(id)
   212→			stateMgr.Unregister(id)
   213→			return nil, fmt.Errorf("failed to create transparent proxy: %w", err)
   214→		}
   215→
   216→		proxy.Start()
   217→
   218→		fwRules = sandboxnet.NewNFTablesRules(linuxMachine.TapName(), gatewayIP, proxy.HTTPPort(), proxy.HTTPSPort(), proxy.PassthroughPort(), config.Network.GetDNSServers())
   219→		if err := fwRules.Setup(); err != nil {
   220→			proxy.Close()
   221→			machine.Close(ctx)
   222→			subnetAlloc.Release(id)
   223→			stateMgr.Unregister(id)
   224→			return nil, fmt.Errorf("failed to setup firewall rules: %w", err)
   225→		}
   226→	}
   227→
   228→	// Set up basic NAT for guest network access using nftables
   229→	natRules := sandboxnet.NewNFTablesNAT(linuxMachine.TapName())
   230→	if err := natRules.Setup(); err != nil {
   231→		fmt.Fprintf(os.Stderr, "Warning: failed to setup NAT: %v\n", err)
   232→		natRules = nil
   233→	}
   234→
   235→	// Create VFS providers
   236→	vfsProviders := make(map[string]vfs.Provider)
   237→	if config.VFS != nil && config.VFS.Mounts != nil {
   238→		for path, mount := range config.VFS.Mounts {
   239→			provider := createProvider(mount)
   240→			if provider != nil {
   241→				vfsProviders[path] = provider
   242→			}
   243→		}
   244→	}
   245→	if len(vfsProviders) == 0 {
   246→		vfsProviders[workspace] = vfs.NewMemoryProvider()
   247→	}
   248→	vfsRoot := vfs.NewMountRouter(vfsProviders)
   249→
   250→	// Create VFS server for guest FUSE daemon connections
   251→	vfsServer := vfs.NewVFSServer(vfsRoot)
   252→
   253→	// Start VFS server on the vsock UDS path for VFS port
   254→	vfsSocketPath := fmt.Sprintf("%s_%d", vmConfig.VsockPath, linux.VsockPortVFS)
   255→	vfsStopFunc, err := vfsServer.ServeUDSBackground(vfsSocketPath)
   256→	if err != nil {
   257→		if proxy != nil {
   258→			proxy.Close()
   259→		}
   260→		if fwRules != nil {
   261→			fwRules.Cleanup()
   262→		}
   263→		machine.Close(ctx)
   264→		subnetAlloc.Release(id)
   265→		stateMgr.Unregister(id)
   266→		return nil, fmt.Errorf("failed to start VFS server: %w", err)
   267→	}
   268→
   269→	return &Sandbox{
   270→		id:          id,
   271→		config:      config,
   272→		machine:     machine,
   273→		proxy:       proxy,
   274→		fwRules:     fwRules,
   275→		natRules:    natRules,
   276→		policy:      policyEngine,
   277→		vfsRoot:     vfsRoot,
   278→		vfsServer:   vfsServer,
   279→		vfsStopFunc: vfsStopFunc,
   280→		events:      events,
   281→		stateMgr:    stateMgr,
   282→		tapName:     linuxMachine.TapName(),
   283→		caPool:      caPool,
   284→		subnetInfo:  subnetInfo,
   285→		subnetAlloc: subnetAlloc,
   286→		workspace:   workspace,
   287→		rootfsPath:  vmRootfsPath,
   288→	}, nil
   289→}
   290→
   291→// ID returns the sandbox identifier.
   292→func (s *Sandbox) ID() string { return s.id }
   293→
   294→// Config returns the sandbox configuration.
   295→func (s *Sandbox) Config() *api.Config { return s.config }
   296→
   297→// Workspace returns the VFS mount point path.
   298→func (s *Sandbox) Workspace() string { return s.workspace }
   299→
   300→// Machine returns the underlying VM machine for advanced operations.
   301→func (s *Sandbox) Machine() vm.Machine { return s.machine }
   302→
   303→// Policy returns the policy engine.
   304→func (s *Sandbox) Policy() *policy.Engine { return s.policy }
   305→
   306→func (s *Sandbox) CAPool() *sandboxnet.CAPool { return s.caPool }
   307→
   308→// Start starts the sandbox VM.
   309→func (s *Sandbox) Start(ctx context.Context) error {
   310→	return s.machine.Start(ctx)
   311→}
   312→
   313→// Stop stops the sandbox VM.
   314→func (s *Sandbox) Stop(ctx context.Context) error {
   315→	return s.machine.Stop(ctx)
   316→}
   317→
   318→func (s *Sandbox) PrepareExecEnv() *api.ExecOptions {
   319→	return prepareExecEnv(s.config, s.caPool, s.policy)
   320→}
   321→
   322→func (s *Sandbox) Exec(ctx context.Context, command string, opts *api.ExecOptions) (*api.ExecResult, error) {
   323→	return execCommand(ctx, s.machine, s.config, s.caPool, s.policy, command, opts)
   324→}
   325→
   326→func (s *Sandbox) WriteFile(ctx context.Context, path string, content []byte, mode uint32) error {
   327→	return writeFile(s.vfsRoot, path, content, mode)
   328→}
   329→
   330→func (s *Sandbox) ReadFile(ctx context.Context, path string) ([]byte, error) {
   331→	return readFile(s.vfsRoot, path)
   332→}
   333→
   334→func (s *Sandbox) ReadFileTo(ctx context.Context, path string, w io.Writer) (int64, error) {
   335→	return readFileTo(s.vfsRoot, path, w)
   336→}
   337→
   338→func (s *Sandbox) ListFiles(ctx context.Context, path string) ([]api.FileInfo, error) {
   339→	return listFiles(s.vfsRoot, path)
   340→}
   341→
   342→// Events returns a channel for receiving sandbox events.
   343→func (s *Sandbox) Events() <-chan api.Event {
   344→	return s.events
   345→}
   346→
   347→// Close shuts down the sandbox and releases all resources.
   348→func (s *Sandbox) Close(ctx context.Context) error {
   349→	var errs []error
   350→
   351→	if s.vfsStopFunc != nil {
   352→		s.vfsStopFunc()
   353→	}
   354→	if s.fwRules != nil {
   355→		if err := s.fwRules.Cleanup(); err != nil {
   356→			errs = append(errs, fmt.Errorf("firewall cleanup: %w", err))
   357→		}
   358→	}
   359→	if s.natRules != nil {
   360→		if err := s.natRules.Cleanup(); err != nil {
   361→			errs = append(errs, fmt.Errorf("NAT cleanup: %w", err))
   362→		}
   363→	}
   364→	if s.proxy != nil {
   365→		s.proxy.Close()
   366→	}
   367→
   368→	// Release subnet allocation
   369→	if s.subnetAlloc != nil {
   370→		s.subnetAlloc.Release(s.id)
   371→	}
   372→
   373→	close(s.events)
   374→	s.stateMgr.Unregister(s.id)
   375→	if err := s.machine.Close(ctx); err != nil {
   376→		errs = append(errs, fmt.Errorf("machine close: %w", err))
   377→	}
   378→
   379→	// Remove rootfs copy to save disk space
   380→	rootfsCopy := s.stateMgr.Dir(s.id) + "/rootfs.ext4"
   381→	os.Remove(rootfsCopy)
   382→
   383→	if len(errs) > 0 {
   384→		fmt.Fprintf(os.Stderr, "Warning: cleanup errors: %v\n", errs)
   385→	}
   386→	return nil
   387→}
   388→
   389→func createProvider(mount api.MountConfig) vfs.Provider {
   390→	switch mount.Type {
   391→	case "memory":
   392→		return vfs.NewMemoryProvider()
   393→	case "real_fs":
   394→		p := vfs.NewRealFSProvider(mount.HostPath)
   395→		if mount.Readonly {
   396→			return vfs.NewReadonlyProvider(p)
   397→		}
   398→		return p
   399→	case "overlay":
   400→		var upper, lower vfs.Provider
   401→		if mount.Upper != nil {
   402→			upper = createProvider(*mount.Upper)
   403→		} else {
   404→			upper = vfs.NewMemoryProvider()
   405→		}
   406→		if mount.Lower != nil {
   407→			lower = createProvider(*mount.Lower)
   408→		}
   409→		if upper != nil && lower != nil {
   410→			return vfs.NewOverlayProvider(upper, lower)
   411→		}
   412→		return upper
   413→	default:
   414→		return vfs.NewMemoryProvider()
   415→	}
   416→}
   417→
   418→func copyRootfs(src, dst string) error {
   419→	srcFile, err := os.Open(src)
   420→	if err != nil {
   421→		return fmt.Errorf("open source: %w", err)
   422→	}
   423→	defer srcFile.Close()
   424→
   425→	dstFile, err := os.Create(dst)
   426→	if err != nil {
   427→		return fmt.Errorf("create dest: %w", err)
   428→	}
   429→	defer dstFile.Close()
   430→
   431→	// Try copy-on-write clone first (FICLONE ioctl)
   432→	// Works on btrfs, xfs (with reflink), bcachefs, etc.
   433→	err = unix.IoctlFileClone(int(dstFile.Fd()), int(srcFile.Fd()))
   434→	if err == nil {
   435→		return nil
   436→	}
   437→
   438→	// Fall back to regular copy
   439→	fmt.Fprintf(os.Stderr, "Note: copy-on-write not supported (%v), using regular copy\n", err)
