     1→package sandbox
     2→
     3→import (
     4→	"context"
     5→	"encoding/binary"
     6→	"encoding/json"
     7→	"fmt"
     8→	"io"
     9→	"net"
    10→	"os"
    11→	"sync"
    12→
    13→	"github.com/jingkaihe/matchlock/pkg/api"
    14→	"github.com/jingkaihe/matchlock/pkg/vm"
    15→)
    16→
    17→const (
    18→	relayMsgExec            uint8 = 1
    19→	relayMsgExecResult      uint8 = 2
    20→	relayMsgExecInteractive uint8 = 3
    21→	relayMsgStdout          uint8 = 4
    22→	relayMsgStderr          uint8 = 5
    23→	relayMsgStdin           uint8 = 6
    24→	relayMsgExit            uint8 = 7
    25→)
    26→
    27→type relayExecRequest struct {
    28→	Command    string `json:"command"`
    29→	WorkingDir string `json:"working_dir,omitempty"`
    30→	User       string `json:"user,omitempty"`
    31→}
    32→
    33→type relayExecInteractiveRequest struct {
    34→	Command    string `json:"command"`
    35→	WorkingDir string `json:"working_dir,omitempty"`
    36→	User       string `json:"user,omitempty"`
    37→	Rows       uint16 `json:"rows"`
    38→	Cols       uint16 `json:"cols"`
    39→}
    40→
    41→type relayExecResult struct {
    42→	ExitCode int    `json:"exit_code"`
    43→	Stdout   []byte `json:"stdout,omitempty"`
    44→	Stderr   []byte `json:"stderr,omitempty"`
    45→	Error    string `json:"error,omitempty"`
    46→}
    47→
    48→// ExecRelay serves exec requests from external processes via a Unix socket.
    49→// This allows `matchlock exec` to run commands in a VM owned by another process.
    50→type ExecRelay struct {
    51→	sb       *Sandbox
    52→	listener net.Listener
    53→	mu       sync.Mutex
    54→	stopped  bool
    55→}
    56→
    57→func NewExecRelay(sb *Sandbox) *ExecRelay {
    58→	return &ExecRelay{sb: sb}
    59→}
    60→
    61→func (r *ExecRelay) Start(socketPath string) error {
    62→	os.Remove(socketPath)
    63→	listener, err := net.Listen("unix", socketPath)
    64→	if err != nil {
    65→		return fmt.Errorf("listen on %s: %w", socketPath, err)
    66→	}
    67→	r.listener = listener
    68→
    69→	go func() {
    70→		for {
    71→			conn, err := listener.Accept()
    72→			if err != nil {
    73→				r.mu.Lock()
    74→				stopped := r.stopped
    75→				r.mu.Unlock()
    76→				if stopped {
    77→					return
    78→				}
    79→				continue
    80→			}
    81→			go r.handleConn(conn)
    82→		}
    83→	}()
    84→
    85→	return nil
    86→}
    87→
    88→func (r *ExecRelay) Stop() {
    89→	r.mu.Lock()
    90→	r.stopped = true
    91→	r.mu.Unlock()
    92→	if r.listener != nil {
    93→		r.listener.Close()
    94→	}
    95→}
    96→
    97→func (r *ExecRelay) handleConn(conn net.Conn) {
    98→	defer conn.Close()
    99→
   100→	msgType, data, err := readRelayMsg(conn)
   101→	if err != nil {
   102→		return
   103→	}
   104→
   105→	switch msgType {
   106→	case relayMsgExec:
   107→		r.handleExec(conn, data)
   108→	case relayMsgExecInteractive:
   109→		r.handleExecInteractive(conn, data)
   110→	}
   111→}
   112→
   113→func (r *ExecRelay) handleExec(conn net.Conn, data []byte) {
   114→	var req relayExecRequest
   115→	if err := json.Unmarshal(data, &req); err != nil {
   116→		sendRelayResult(conn, &relayExecResult{ExitCode: 1, Error: err.Error()})
   117→		return
   118→	}
   119→
   120→	opts := r.sb.PrepareExecEnv()
   121→	if req.WorkingDir != "" {
   122→		opts.WorkingDir = req.WorkingDir
   123→	}
   124→	if req.User != "" {
   125→		opts.User = req.User
   126→	}
   127→
   128→	result, err := r.sb.Exec(context.Background(), req.Command, opts)
   129→	if err != nil {
   130→		sendRelayResult(conn, &relayExecResult{ExitCode: 1, Error: err.Error()})
   131→		return
   132→	}
   133→
   134→	sendRelayResult(conn, &relayExecResult{
   135→		ExitCode: result.ExitCode,
   136→		Stdout:   result.Stdout,
   137→		Stderr:   result.Stderr,
   138→	})
   139→}
   140→
   141→func (r *ExecRelay) handleExecInteractive(conn net.Conn, data []byte) {
   142→	var req relayExecInteractiveRequest
   143→	if err := json.Unmarshal(data, &req); err != nil {
   144→		sendRelayMsg(conn, relayMsgExit, []byte{0, 0, 0, 1})
   145→		return
   146→	}
   147→
   148→	interactiveMachine, ok := r.sb.Machine().(vm.InteractiveMachine)
   149→	if !ok {
   150→		sendRelayMsg(conn, relayMsgExit, []byte{0, 0, 0, 1})
   151→		return
   152→	}
   153→
   154→	opts := r.sb.PrepareExecEnv()
   155→	if req.WorkingDir != "" {
   156→		opts.WorkingDir = req.WorkingDir
   157→	}
   158→	if req.User != "" {
   159→		opts.User = req.User
   160→	}
   161→
   162→	stdinReader, stdinWriter := io.Pipe()
   163→	stdoutWriter := &relayWriter{conn: conn, msgType: relayMsgStdout}
   164→
   165→	// Read stdin from relay client and write to pipe
   166→	go func() {
   167→		defer stdinWriter.Close()
   168→		for {
   169→			msgType, data, err := readRelayMsg(conn)
   170→			if err != nil {
   171→				return
   172→			}
   173→			if msgType == relayMsgStdin {
   174→				stdinWriter.Write(data)
   175→			}
   176→		}
   177→	}()
   178→
   179→	resizeCh := make(chan [2]uint16, 1)
   180→
   181→	exitCode, err := interactiveMachine.ExecInteractive(
   182→		context.Background(), req.Command, opts,
   183→		req.Rows, req.Cols,
   184→		stdinReader, stdoutWriter, resizeCh,
   185→	)
   186→	if err != nil {
   187→		exitCode = 1
   188→	}
   189→
   190→	exitData := make([]byte, 4)
   191→	binary.BigEndian.PutUint32(exitData, uint32(exitCode))
   192→	sendRelayMsg(conn, relayMsgExit, exitData)
   193→}
   194→
   195→// relayWriter forwards writes to the relay connection as messages.
   196→type relayWriter struct {
   197→	conn    net.Conn
   198→	msgType uint8
   199→}
   200→
   201→func (w *relayWriter) Write(p []byte) (int, error) {
   202→	if err := sendRelayMsg(w.conn, w.msgType, p); err != nil {
   203→		return 0, err
   204→	}
   205→	return len(p), nil
   206→}
   207→
   208→func readRelayMsg(conn net.Conn) (uint8, []byte, error) {
   209→	header := make([]byte, 5)
   210→	if _, err := io.ReadFull(conn, header); err != nil {
   211→		return 0, nil, err
   212→	}
   213→
   214→	msgType := header[0]
   215→	length := binary.BigEndian.Uint32(header[1:])
   216→
   217→	if length == 0 {
   218→		return msgType, nil, nil
   219→	}
   220→
   221→	data := make([]byte, length)
   222→	if _, err := io.ReadFull(conn, data); err != nil {
   223→		return 0, nil, err
   224→	}
   225→
   226→	return msgType, data, nil
   227→}
   228→
   229→func sendRelayMsg(conn net.Conn, msgType uint8, data []byte) error {
   230→	header := make([]byte, 5)
   231→	header[0] = msgType
   232→	binary.BigEndian.PutUint32(header[1:], uint32(len(data)))
   233→	if _, err := conn.Write(header); err != nil {
   234→		return err
   235→	}
   236→	if len(data) > 0 {
   237→		if _, err := conn.Write(data); err != nil {
   238→			return err
   239→		}
   240→	}
   241→	return nil
   242→}
   243→
   244→func sendRelayResult(conn net.Conn, result *relayExecResult) {
   245→	data, _ := json.Marshal(result)
   246→	sendRelayMsg(conn, relayMsgExecResult, data)
   247→}
