//go:build linux

package sandbox

import (
	"context"
	"fmt"
	"io"
	"net"
	"os"
	"sync/atomic"

	"github.com/jingkaihe/matchlock/pkg/api"
	matchlocksandbox "github.com/jingkaihe/matchlock/pkg/sandbox"
	"github.com/jingkaihe/matchlock/pkg/vfs"
)

// linuxRuntime implements Runtime using Matchlock with Firecracker microVMs.
type linuxRuntime struct {
	vmCounter  atomic.Int64
	kernelPath string
	rootfsPath string
}

// NewRuntime creates a new Linux runtime using Firecracker via Matchlock.
func NewRuntime() (Runtime, error) {
	// Check for KVM availability
	if _, err := os.Stat("/dev/kvm"); os.IsNotExist(err) {
		return nil, fmt.Errorf("%w: /dev/kvm not available", ErrUnsupportedPlatform)
	}

	return &linuxRuntime{
		kernelPath: matchlocksandbox.DefaultKernelPath(),
		rootfsPath: "", // Must be set via config
	}, nil
}

// Create creates a new Firecracker microVM using Matchlock.
func (r *linuxRuntime) Create(ctx context.Context, config *Config) (VM, error) {
	if config == nil {
		config = &Config{}
	}

	// Build Matchlock API config
	apiConfig := &api.Config{
		Resources: &api.Resources{
			CPUs:       1,
			MemoryMB:   512,
			DiskSizeMB: 1024,
		},
	}

	if config.Resources != nil {
		if config.Resources.CPUs > 0 {
			apiConfig.Resources.CPUs = config.Resources.CPUs
		}
		if config.Resources.MemoryMB > 0 {
			apiConfig.Resources.MemoryMB = config.Resources.MemoryMB
		}
		if config.Resources.DiskMB > 0 {
			apiConfig.Resources.DiskSizeMB = config.Resources.DiskMB
		}
	}

	// Configure VFS for workspace mounting
	if config.WorkspaceRoot != "" {
		workspace := "/workspace"
		if config.Policy != nil && config.Policy.Filesystem != nil &&
			config.Policy.Filesystem.WorkspaceMountPoint != "" {
			workspace = config.Policy.Filesystem.WorkspaceMountPoint
		}

		apiConfig.VFS = &api.VFSConfig{
			Workspace: workspace,
			Mounts: map[string]api.MountConfig{
				workspace: {
					Type:     "real_fs",
					HostPath: config.WorkspaceRoot,
				},
			},
		}
	}

	// Configure network policy
	if config.Policy != nil && config.Policy.Network != nil {
		apiConfig.Network = &api.NetworkConfig{
			BlockPrivateIPs: true,
		}
		if !config.Policy.Network.BlockAllEgress {
			apiConfig.Network.AllowedHosts = config.Policy.Network.AllowedHosts
		}
	}

	// Determine rootfs path
	rootfsPath := config.Image
	if rootfsPath == "" {
		rootfsPath = r.rootfsPath
	}
	if rootfsPath == "" {
		return nil, fmt.Errorf("rootfs image path required")
	}

	// Create Matchlock sandbox
	opts := &matchlocksandbox.Options{
		KernelPath: r.kernelPath,
		RootfsPath: rootfsPath,
	}

	sb, err := matchlocksandbox.New(ctx, apiConfig, opts)
	if err != nil {
		return nil, fmt.Errorf("create matchlock sandbox: %w", err)
	}

	// Start the VM
	if err := sb.Start(ctx); err != nil {
		sb.Close(ctx)
		return nil, fmt.Errorf("start sandbox: %w", err)
	}

	return &linuxVM{
		id:      sb.ID(),
		state:   VMStateRunning,
		config:  config,
		sandbox: sb,
	}, nil
}

// linuxVM represents a Firecracker microVM managed by Matchlock.
type linuxVM struct {
	id      string
	state   VMState
	config  *Config
	sandbox *matchlocksandbox.Sandbox
}

// ID returns the VM identifier.
func (v *linuxVM) ID() string {
	return v.id
}

// State returns the VM state.
func (v *linuxVM) State() VMState {
	return v.state
}

// AgentConn returns a connection to the guest agent.
// On Linux with Matchlock, we use the exec relay socket.
func (v *linuxVM) AgentConn() (net.Conn, error) {
	// Matchlock doesn't expose a direct vsock connection in its API.
	// Instead, commands are executed via sandbox.Exec().
	// Return a stub that indicates this VM uses direct Matchlock execution.
	return nil, fmt.Errorf("linux runtime uses Matchlock exec, not agent connection")
}

// Sandbox returns the underlying Matchlock sandbox for direct command execution.
func (v *linuxVM) Sandbox() *matchlocksandbox.Sandbox {
	return v.sandbox
}

// Exec executes a command in the VM using Matchlock's built-in mechanism.
func (v *linuxVM) Exec(ctx context.Context, command string, opts *api.ExecOptions) (*api.ExecResult, error) {
	return v.sandbox.Exec(ctx, command, opts)
}

// WriteFile writes a file to the VM's VFS.
func (v *linuxVM) WriteFile(ctx context.Context, path string, content []byte, mode uint32) error {
	return v.sandbox.WriteFile(ctx, path, content, mode)
}

// ReadFile reads a file from the VM's VFS.
func (v *linuxVM) ReadFile(ctx context.Context, path string) ([]byte, error) {
	return v.sandbox.ReadFile(ctx, path)
}

// Close stops and destroys the VM.
func (v *linuxVM) Close() error {
	v.state = VMStateStopped
	return v.sandbox.Close(context.Background())
}

// MatchlockVM is an interface for VMs that use Matchlock for execution.
// This allows the executor to detect and use the native Matchlock exec path.
type MatchlockVM interface {
	VM
	Sandbox() *matchlocksandbox.Sandbox
	Exec(ctx context.Context, command string, opts *api.ExecOptions) (*api.ExecResult, error)
	WriteFile(ctx context.Context, path string, content []byte, mode uint32) error
	ReadFile(ctx context.Context, path string) ([]byte, error)
}

// Ensure linuxVM implements MatchlockVM
var _ MatchlockVM = (*linuxVM)(nil)

// VFSProvider wraps a Matchlock VFS provider for use with our sandbox.
type VFSProvider struct {
	provider vfs.Provider
}

// NewVFSProvider creates a new VFS provider wrapping a Matchlock provider.
func NewVFSProvider(hostPath string) *VFSProvider {
	return &VFSProvider{
		provider: vfs.NewRealFSProvider(hostPath),
	}
}

// Open opens a file in the VFS.
func (p *VFSProvider) Open(path string, flags int, mode os.FileMode) (io.ReadWriteCloser, error) {
	return p.provider.Open(path, flags, mode)
}

// Create creates a new file in the VFS.
func (p *VFSProvider) Create(path string, mode os.FileMode) (io.WriteCloser, error) {
	return p.provider.Create(path, mode)
}

// ReadDir reads a directory in the VFS.
func (p *VFSProvider) ReadDir(path string) ([]os.DirEntry, error) {
	entries, err := p.provider.ReadDir(path)
	if err != nil {
		return nil, err
	}

	result := make([]os.DirEntry, len(entries))
	for i, e := range entries {
		result[i] = vfsDirEntry{e}
	}
	return result, nil
}

type vfsDirEntry struct {
	vfs.DirEntry
}

func (e vfsDirEntry) Name() string {
	return e.DirEntry.Name()
}

func (e vfsDirEntry) IsDir() bool {
	return e.DirEntry.IsDir()
}

func (e vfsDirEntry) Type() os.FileMode {
	return e.DirEntry.Type()
}

func (e vfsDirEntry) Info() (os.FileInfo, error) {
	return e.DirEntry.Info()
}

