// darwinRuntime implements Runtime using Matchlock with Apple Virtualization.framework.
type darwinRuntime struct {
	vmCounter     atomic.Int64
	kernelPath    string
	initramfsPath string
	rootfsPath    string
}

// NewRuntime creates a new Darwin runtime using Virtualization.framework via Matchlock.
func NewRuntime() (Runtime, error) {
	// Virtualization.framework is only available on Apple Silicon
	if runtime.GOARCH != "arm64" {
		return nil, fmt.Errorf("%w: darwin/amd64 not supported", ErrUnsupportedPlatform)
	}

	return &darwinRuntime{
		kernelPath:    matchlocksandbox.DefaultKernelPath(),
		initramfsPath: matchlocksandbox.DefaultInitramfsPath(),
		rootfsPath:    "", // Must be set via config
	}, nil
}

// Create creates a new VM using Virtualization.framework via Matchlock.
func (r *darwinRuntime) Create(ctx context.Context, config *Config) (VM, error) {
	if config == nil {
		config = &Config{}
	}

	// Build Matchlock API config
	apiConfig := &api.Config{
		Resources: &api.Resources{
			CPUs:       1,
			MemoryMB:   512,
			DiskSizeMB: 1024,
		},
	}

	if config.Resources != nil {
		if config.Resources.CPUs > 0 {
			apiConfig.Resources.CPUs = config.Resources.CPUs
		}
		if config.Resources.MemoryMB > 0 {
			apiConfig.Resources.MemoryMB = config.Resources.MemoryMB
		}
		if config.Resources.DiskMB > 0 {
			apiConfig.Resources.DiskSizeMB = config.Resources.DiskMB
		}
	}

	// Configure VFS for workspace mounting
	if config.WorkspaceRoot != "" {
		workspace := "/workspace"
		if config.Policy != nil && config.Policy.Filesystem != nil &&
			config.Policy.Filesystem.WorkspaceMountPoint != "" {
			workspace = config.Policy.Filesystem.WorkspaceMountPoint
		}

		apiConfig.VFS = &api.VFSConfig{
			Workspace: workspace,
			Mounts: map[string]api.MountConfig{
				workspace: {
					Type:     "real_fs",
					HostPath: config.WorkspaceRoot,
				},
			},
		}
	}

	// Configure network policy
	if config.Policy != nil && config.Policy.Network != nil {
		apiConfig.Network = &api.NetworkConfig{
			BlockPrivateIPs: true,
		}
		if !config.Policy.Network.BlockAllEgress {
			apiConfig.Network.AllowedHosts = config.Policy.Network.AllowedHosts
		}
	}

	// Determine rootfs path
	rootfsPath := config.Image
	if rootfsPath == "" {
		rootfsPath = r.rootfsPath
	}
	if rootfsPath == "" {
		return nil, fmt.Errorf("rootfs image path required")
	}

	// Create Matchlock sandbox
	opts := &matchlocksandbox.Options{
		KernelPath:    r.kernelPath,
		InitramfsPath: r.initramfsPath,
		RootfsPath:    rootfsPath,
	}

	sb, err := matchlocksandbox.New(ctx, apiConfig, opts)
	if err != nil {
		return nil, fmt.Errorf("create matchlock sandbox: %w", err)
	}

	// Start the VM
	if err := sb.Start(ctx); err != nil {
		sb.Close(ctx)
		return nil, fmt.Errorf("start sandbox: %w", err)
	}

	return &darwinVM{
		id:      sb.ID(),
		state:   VMStateRunning,
		config:  config,
		sandbox: sb,
	}, nil
}

