func TestEnvironmentPolicy_ScrubEnvironment(t *testing.T) {
	tsuite := []struct {
		name     string
		policy   *EnvironmentPolicy
		input    []string
		expected []string
	}{
		{
			name:   "nil policy passes all",
			policy: nil,
			input: []string{
				"PATH=/usr/bin",
				"GITHUB_TOKEN=secret",
			},
			expected: []string{
				"PATH=/usr/bin",
				"GITHUB_TOKEN=secret",
			},
		},
		{
			name: "scrubbing disabled passes all",
			policy: &EnvironmentPolicy{
				ScrubSensitive: false,
			},
			input: []string{
				"PATH=/usr/bin",
				"GITHUB_TOKEN=secret",
			},
			expected: []string{
				"PATH=/usr/bin",
				"GITHUB_TOKEN=secret",
			},
		},
		{
			name:   "default policy blocks common secrets",
			policy: DefaultEnvironmentPolicy(),
			input: []string{
				"PATH=/usr/bin",
				"HOME=/home/user",
				"GITHUB_TOKEN=ghp_secret123",
				"AWS_SECRET_ACCESS_KEY=wJalrXUtnFEMI",
				"OPENAI_API_KEY=sk-proj-abc123",
				"USER=testuser",
			},
			expected: []string{
				"PATH=/usr/bin",
				"HOME=/home/user",
				"USER=testuser",
			},
		},
		{
			name:   "default policy blocks pattern matches",
			policy: DefaultEnvironmentPolicy(),
			input: []string{
				"PATH=/usr/bin",
				"MY_SECRET_KEY=secret",
				"DATABASE_PASSWORD=pass123",
				"CUSTOM_API_KEY=key123",
				"SAFE_VAR=value",
			},
			expected: []string{
				"PATH=/usr/bin",
				"SAFE_VAR=value",
			},
		},
		{
			name: "allowlist restricts to specified vars",
			policy: &EnvironmentPolicy{
				ScrubSensitive: true,
				AllowedVars:    []string{"PATH", "HOME"},
			},
			input: []string{
				"PATH=/usr/bin",
				"HOME=/home/user",
				"USER=testuser",
				"LANG=en_US.UTF-8",
			},
			expected: []string{
				"PATH=/usr/bin",
				"HOME=/home/user",
			},
		},
		{
			name: "blocklist with custom vars",
			policy: &EnvironmentPolicy{
				ScrubSensitive: true,
				BlockedVars:    []string{"CUSTOM_VAR", "ANOTHER_VAR"},
			},
			input: []string{
				"PATH=/usr/bin",
				"CUSTOM_VAR=blocked",
				"ANOTHER_VAR=also_blocked",
				"SAFE_VAR=allowed",
			},
			expected: []string{
				"PATH=/usr/bin",
				"SAFE_VAR=allowed",
			},
		},
		{
			name: "custom pattern blocks matching vars",
			policy: &EnvironmentPolicy{
				ScrubSensitive:  true,
				BlockedPatterns: []string{`^MY_.*`},
			},
			input: []string{
				"PATH=/usr/bin",
				"MY_VAR=blocked",
				"MY_OTHER=also_blocked",
				"NOT_MY_VAR=allowed",
			},
			expected: []string{
				"PATH=/usr/bin",
				"NOT_MY_VAR=allowed",
			},
		},
		{
			name:   "malformed env vars are skipped",
			policy: DefaultEnvironmentPolicy(),
			input: []string{
				"PATH=/usr/bin",
				"MALFORMED",
				"GOOD=value",
			},
			expected: []string{
				"PATH=/usr/bin",
				"GOOD=value",
			},
		},
		{
			name:   "empty value is preserved",
			policy: DefaultEnvironmentPolicy(),
			input: []string{
				"EMPTY=",
				"PATH=/usr/bin",
			},
			expected: []string{
				"EMPTY=",
				"PATH=/usr/bin",
			},
		},
		{
			name:   "case insensitive pattern matching",
			policy: DefaultEnvironmentPolicy(),
			input: []string{
				"my_secret_key=secret",
				"My_Password=pass",
				"MY_API_KEY=key",
				"safe_var=value",
			},
			expected: []string{
				"safe_var=value",
			},
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			result := tc.policy.ScrubEnvironment(tc.input)
			assert.Equal(t, tc.expected, result)
		})
	}
}

func TestDefaultEnvironmentPolicy(t *testing.T) {
	p := DefaultEnvironmentPolicy()

	assert.True(t, p.ScrubSensitive, "ScrubSensitive should be true by default")
	assert.NotEmpty(t, p.BlockedVars, "BlockedVars should have entries")
	assert.NotEmpty(t, p.BlockedPatterns, "BlockedPatterns should have entries")

	// Verify common secrets are in blocked list
	blocked := make(map[string]bool)
	for _, v := range p.BlockedVars {
		blocked[v] = true
	}

	assert.True(t, blocked["GITHUB_TOKEN"], "GITHUB_TOKEN should be blocked")
	assert.True(t, blocked["AWS_SECRET_ACCESS_KEY"], "AWS_SECRET_ACCESS_KEY should be blocked")
	assert.True(t, blocked["OPENAI_API_KEY"], "OPENAI_API_KEY should be blocked")
	assert.True(t, blocked["ANTHROPIC_API_KEY"], "ANTHROPIC_API_KEY should be blocked")
}

