// Package sandbox provides a secure execution environment for running
// commands from extensions. Commands run inside an isolated virtual machine,
// protecting the host system from malicious or buggy extension code.
package sandbox

import (
	"bytes"
	"context"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"net"
	"strings"
	"sync"
	"sync/atomic"
	"syscall"
	"time"

	"github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
	"github.com/unstablebuild/rune-go-sdk/sandbox/sandboxrpc"
	"google.golang.org/grpc"
	"google.golang.org/grpc/credentials/insecure"
)

const agentConnectTimeout = 30 * time.Second

// Ensure Executor implements workspaceapi.Executor
var _ workspaceapi.Executor = (*Executor)(nil)

// Executor implements workspaceapi.Executor by running commands inside a
// sandboxed virtual machine.
type Executor struct {
	config  Config
	runtime Runtime
	vm      VM
	agent   *sandboxrpc.Client
	conn    *grpc.ClientConn
	log     *slog.Logger

	// For ExecutableVM mode
	execVM     ExecutableVM
	pidCounter atomic.Int64
	processes  sync.Map // map[workspaceapi.Pid]context.CancelFunc

	mu     sync.RWMutex
	closed bool
}

// Option is a functional option for configuring an Executor.
type Option func(*Executor)

// WithRuntime sets a custom runtime for the executor.
// This is primarily used for testing.
func WithRuntime(r Runtime) Option {
	return func(e *Executor) {
		e.runtime = r
	}
}

// WithLogger sets a custom logger for the executor.
func WithLogger(log *slog.Logger) Option {
	return func(e *Executor) {
		e.log = log
	}
}

// New creates a new sandbox executor. The VM is started immediately and
// will be ready to accept commands upon return. The caller is responsible
// for calling Close() when the executor is no longer needed.
func New(ctx context.Context, config Config, opts ...Option) (*Executor, error) {
	e := &Executor{
		config: config,
		log:    slog.Default().With("struct", "sandbox.Executor"),
	}

	for _, opt := range opts {
		opt(e)
	}

	// Use default runtime if not provided
	if e.runtime == nil {
		runtime, err := NewRuntime()
		if err != nil {
			return nil, fmt.Errorf("create runtime: %w", err)
		}
		e.runtime = runtime
	}

	// Create the VM
	vm, err := e.runtime.Create(ctx, &config)
	if err != nil {
		return nil, fmt.Errorf("create vm: %w", err)
	}
	e.vm = vm

	// Check if VM supports direct execution (e.g., Matchlock VMs)
	if execVM, ok := vm.(ExecutableVM); ok {
		e.execVM = execVM
		e.log.Info("sandbox executor ready (direct exec)", "vm_id", vm.ID())
		return e, nil
	}

	// Fall back to gRPC agent connection
	if err := e.connectAgent(ctx); err != nil {
		_ = vm.Close()
		return nil, fmt.Errorf("connect agent: %w", err)
	}

	e.log.Info("sandbox executor ready (agent)", "vm_id", vm.ID())
	return e, nil
}

func (e *Executor) connectAgent(ctx context.Context) error {
	timeoutCtx, cancel := context.WithTimeout(ctx, agentConnectTimeout)
	defer cancel()

	// Get connection to the agent
	agentConn, err := e.vm.AgentConn()
	if err != nil {
		return fmt.Errorf("get agent connection: %w", err)
	}

	// Create gRPC connection over the net.Conn
	grpcConn, err := grpc.NewClient(
		"passthrough:///sandbox",
		grpc.WithTransportCredentials(insecure.NewCredentials()),
		grpc.WithContextDialer(func(_ context.Context, _ string) (net.Conn, error) {
			return agentConn, nil
		}),
	)
	if err != nil {
		_ = agentConn.Close()
		return fmt.Errorf("create grpc connection: %w", err)
	}
	e.conn = grpcConn

	// Create the agent client with a background context (lives until Close)
	e.agent = sandboxrpc.NewClient(context.Background(), grpcConn)

	// Ping the agent to verify it's ready
	if err := e.agent.Ping(timeoutCtx); err != nil {
		_ = grpcConn.Close()
		_ = agentConn.Close()
		return fmt.Errorf("ping agent: %w", err)
	}

	return nil
}

// Start starts a command in the sandbox and returns its PID.
// This method implements workspaceapi.Executor.
func (e *Executor) Start(
	ctx context.Context, cmd workspaceapi.Cmd,
) (workspaceapi.Pid, error) {
	e.mu.RLock()
	defer e.mu.RUnlock()

	if e.closed {
		return 0, ErrClosed
	}

	if cmd.Path == "" {
		return 0, ErrInvalidCommand
	}

	// Use direct exec if available
	if e.execVM != nil {
		return e.startWithExec(ctx, cmd)
	}

	// Fall back to agent
	return e.agent.StartCommand(ctx, cmd)
}

// startWithExec uses the VM's direct Exec method.
func (e *Executor) startWithExec(ctx context.Context, cmd workspaceapi.Cmd) (workspaceapi.Pid, error) {
	// Build command string
	command := cmd.Path
	if len(cmd.Args) > 0 {
		command = command + " " + strings.Join(cmd.Args, " ")
	}

	// Create exec options
	opts := &ExecOptions{
		WorkingDir: cmd.Dir,
		Env:        make(map[string]string),
	}

	// Parse environment variables
	for _, env := range cmd.Env {
		parts := strings.SplitN(env, "=", 2)
		if len(parts) == 2 {
			opts.Env[parts[0]] = parts[1]
		}
	}

	// Set up I/O
	opts.Stdin = cmd.Stdin
	opts.Stdout = cmd.Stdout
	opts.Stderr = cmd.Stderr

	// Generate PID
	pid := workspaceapi.Pid(e.pidCounter.Add(1))

	// Create cancellable context for this process
	procCtx, cancel := context.WithCancel(ctx)
	e.processes.Store(pid, cancel)

	// Run command in background
	go func() {
		defer e.processes.Delete(pid)
		defer cancel()

		var stdoutBuf, stderrBuf bytes.Buffer
		execOpts := &ExecOptions{
			WorkingDir: opts.WorkingDir,
			Env:        opts.Env,
		}

		// If streaming I/O is provided, pass it through
		if opts.Stdout != nil {
			execOpts.Stdout = opts.Stdout
		} else {
			execOpts.Stdout = &stdoutBuf
		}
		if opts.Stderr != nil {
			execOpts.Stderr = opts.Stderr
		} else {
			execOpts.Stderr = &stderrBuf
		}
		if opts.Stdin != nil {
			execOpts.Stdin = opts.Stdin
		}

		result, err := e.execVM.Exec(procCtx, command, execOpts)

		// Notify watcher
		if cmd.Watcher != nil && cmd.Watcher.WatchProcess() != nil {
			var watchErr error
			if err != nil {
				watchErr = err
			} else if result != nil && result.ExitCode != 0 {
				watchErr = fmt.Errorf("exit status %d", result.ExitCode)
			}

			select {
			case cmd.Watcher.WatchProcess() <- watchErr:
			case <-time.After(2 * time.Minute):
				e.log.Warn("watcher not ready, dropping result")
			}
		}

		// Close output streams if they implement io.Closer
		if closer, ok := cmd.Stdout.(io.Closer); ok {
			_ = closer.Close()
		}
		if closer, ok := cmd.Stderr.(io.Closer); ok {
			_ = closer.Close()
		}
	}()

	return pid, nil
}

// Signal sends a signal to a process running in the sandbox.
// This method implements workspaceapi.Executor.
func (e *Executor) Signal(pid workspaceapi.Pid, sig syscall.Signal) error {
	e.mu.RLock()
	defer e.mu.RUnlock()

	if e.closed {
		return ErrClosed
	}

	if pid <= 0 {
		return ErrProcessNotFound
	}

	// Use direct cancellation for ExecutableVM
	if e.execVM != nil {
		v, ok := e.processes.Load(pid)
		if !ok {
			return ErrProcessNotFound
		}
		cancel := v.(context.CancelFunc)
		// For SIGTERM/SIGKILL, cancel the context
		if sig == syscall.SIGTERM || sig == syscall.SIGKILL {
			cancel()
		}
		return nil
	}

	// Fall back to agent
	return e.agent.Signal(pid, sig)
}

// Close stops the sandbox and releases all resources.
// This method implements io.Closer.
func (e *Executor) Close() error {
	e.mu.Lock()
	defer e.mu.Unlock()

	if e.closed {
		return nil
	}
	e.closed = true

	var errs []error

	// Cancel all running processes
	e.processes.Range(func(_, value any) bool {
		cancel := value.(context.CancelFunc)
		cancel()
		return true
	})

	if e.agent != nil {
		if err := e.agent.Close(); err != nil {
			errs = append(errs, fmt.Errorf("close agent: %w", err))
		}
	}

	if e.conn != nil {
		if err := e.conn.Close(); err != nil {
			errs = append(errs, fmt.Errorf("close grpc conn: %w", err))
		}
	}

	if e.vm != nil {
		if err := e.vm.Close(); err != nil {
			errs = append(errs, fmt.Errorf("close vm: %w", err))
		}
	}

	e.log.Info("sandbox executor closed", "vm_id", e.vm.ID())
	return errors.Join(errs...)
}

// VM returns the underlying VM. This is primarily for testing.
func (e *Executor) VM() VM {
	return e.vm
}

// Config returns the executor's configuration.
func (e *Executor) Config() Config {
	return e.config
}

