			inputEnv: []string{
				"PATH=/usr/bin",
				"GITHUB_TOKEN=ghp_secret123",
				"HOME=/home/user",
			},
			wantPresent: []string{"PATH=/usr/bin", "HOME=/home/user"},
			wantAbsent:  []string{"GITHUB_TOKEN=ghp_secret123"},
		},
		{
			name: "scrubs aws secrets",
			inputEnv: []string{
				"PATH=/usr/bin",
				"AWS_SECRET_ACCESS_KEY=wJalrXUtnFEMI",
				"AWS_ACCESS_KEY_ID=AKIAIOSFODNN7EXAMPLE",
			},
			wantPresent: []string{"PATH=/usr/bin", "AWS_ACCESS_KEY_ID=AKIAIOSFODNN7EXAMPLE"},
			wantAbsent:  []string{"AWS_SECRET_ACCESS_KEY=wJalrXUtnFEMI"},
		},
		{
			name: "scrubs pattern-matched vars",
			inputEnv: []string{
				"SAFE_VAR=value",
				"MY_SECRET_KEY=secret",
				"DATABASE_PASSWORD=pass123",
			},
			wantPresent: []string{"SAFE_VAR=value"},
			wantAbsent:  []string{"MY_SECRET_KEY=secret", "DATABASE_PASSWORD=pass123"},
		},
		{
			name: "preserves safe vars",
			inputEnv: []string{
				"PATH=/usr/bin",
				"HOME=/home/user",
				"USER=testuser",
				"LANG=en_US.UTF-8",
			},
			wantPresent: []string{
				"PATH=/usr/bin",
				"HOME=/home/user",
				"USER=testuser",
				"LANG=en_US.UTF-8",
			},
			wantAbsent: []string{},
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			// Use the internal scrubEnvironment method to verify behavior
			scrubbed := exec.scrubEnvironment(tc.inputEnv)

			for _, want := range tc.wantPresent {
				assert.Contains(t, scrubbed, want, "expected var to be present")
			}

			for _, unwant := range tc.wantAbsent {
				assert.NotContains(t, scrubbed, unwant, "expected var to be scrubbed")
			}
		})
	}
}

