func TestMockExecutor_Start(t *testing.T) {
	tsuite := []struct {
		name     string
		startErr error
		wantErr  bool
	}{
		{
			name:     "success",
			startErr: nil,
			wantErr:  false,
		},
		{
			name:     "with error",
			startErr: errors.New("start failed"),
			wantErr:  true,
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			mock := NewMockExecutor()
			mock.StartErr = tc.startErr

			cmd := workspaceapi.Cmd{
				Path: "/bin/echo",
				Args: []string{"hello"},
			}

			pid, err := mock.Start(context.Background(), cmd)
			if tc.wantErr {
				require.Error(t, err)
				assert.Equal(t, workspaceapi.Pid(0), pid)
				return
			}

			require.NoError(t, err)
			assert.NotZero(t, pid)

			// Verify command was recorded
			commands := mock.Commands()
			assert.Len(t, commands, 1)
			assert.Equal(t, cmd.Path, commands[pid].Path)
		})
	}
}

func TestMockExecutor_Signal(t *testing.T) {
	tsuite := []struct {
		name      string
		signalErr error
		pidExists bool
		wantErr   bool
	}{
		{
			name:      "success",
			signalErr: nil,
			pidExists: true,
			wantErr:   false,
		},
		{
			name:      "with error",
			signalErr: errors.New("signal failed"),
			pidExists: true,
			wantErr:   true,
		},
		{
			name:      "pid not found",
			signalErr: nil,
			pidExists: false,
			wantErr:   true,
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			mock := NewMockExecutor()
			mock.SignalErr = tc.signalErr

			var pid workspaceapi.Pid
			if tc.pidExists {
				var err error
				pid, err = mock.Start(context.Background(), workspaceapi.Cmd{Path: "/bin/sleep"})
				require.NoError(t, err)
			} else {
				pid = 9999
			}

			err := mock.Signal(pid, syscall.SIGTERM)
			if tc.wantErr {
				require.Error(t, err)
				return
			}

			require.NoError(t, err)

			// Verify signal was recorded
			signals := mock.Signals(pid)
			assert.Contains(t, signals, syscall.SIGTERM)
		})
	}
}

func TestMockExecutor_Close(t *testing.T) {
	tsuite := []struct {
		name     string
		closeErr error
		wantErr  bool
	}{
		{
			name:     "success",
			closeErr: nil,
			wantErr:  false,
		},
		{
			name:     "with error",
			closeErr: errors.New("close failed"),
			wantErr:  true,
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			mock := NewMockExecutor()
			mock.CloseErr = tc.closeErr

			assert.False(t, mock.IsClosed())

			err := mock.Close()
			if tc.wantErr {
				require.Error(t, err)
			} else {
				require.NoError(t, err)
			}

			assert.True(t, mock.IsClosed())
		})
	}
}

func TestMockExecutor_MultipleCommands(t *testing.T) {
	mock := NewMockExecutor()

	// Start multiple commands
	pids := make([]workspaceapi.Pid, 3)
	for i := 0; i < 3; i++ {
		pid, err := mock.Start(context.Background(), workspaceapi.Cmd{
			Path: "/bin/echo",
			Args: []string{string(rune('a' + i))},
		})
		require.NoError(t, err)
		pids[i] = pid
	}

	// Verify all were recorded
	commands := mock.Commands()
	assert.Len(t, commands, 3)

	// Each PID should be unique
	assert.NotEqual(t, pids[0], pids[1])
	assert.NotEqual(t, pids[1], pids[2])
	assert.NotEqual(t, pids[0], pids[2])
}

func TestMockExecutor_Watcher(t *testing.T) {
	mock := NewMockExecutor()

	watchCh := make(chan error, 1)
	watcher := &testWatcher{ch: watchCh}

	cmd := workspaceapi.Cmd{
		Path:    "/bin/echo",
		Watcher: watcher,
	}

	_, err := mock.Start(context.Background(), cmd)
	require.NoError(t, err)

	// Watcher should receive nil error (success)
	select {
	case err := <-watchCh:
		assert.NoError(t, err)
	default:
		// Give goroutine time to send
		t.Log("waiting for watcher notification")
	}
}

// testWatcher implements workspaceapi.ProcessWatcher for tests.
type testWatcher struct {
	ch chan error
}

func (w *testWatcher) WatchProcess() chan error {
	return w.ch
}

