func TestMockExecutor_Start(t *testing.T) {
	tsuite := []struct {
		name     string
		startErr error
		wantErr  bool
	}{
		{
			name:     "success",
			startErr: nil,
			wantErr:  false,
		},
		{
			name:     "with error",
			startErr: errors.New("start failed"),
			wantErr:  true,
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			mock := NewMockExecutor()
			mock.StartErr = tc.startErr

			cmd := workspaceapi.Cmd{
				Path: "/bin/echo",
				Args: []string{"hello"},
			}

			pid, err := mock.Start(context.Background(), cmd)
			if tc.wantErr {
				require.Error(t, err)
				assert.Equal(t, workspaceapi.Pid(0), pid)
				return
			}

			require.NoError(t, err)
			assert.NotZero(t, pid)

			// Verify command was recorded
			commands := mock.Commands()
			assert.Len(t, commands, 1)
			assert.Equal(t, cmd.Path, commands[pid].Path)
		})
	}
}

