	tsuite := []struct {
		name      string
		signalErr error
		pidExists bool
		wantErr   bool
	}{
		{
			name:      "success",
			signalErr: nil,
			pidExists: true,
			wantErr:   false,
		},
		{
			name:      "with error",
			signalErr: errors.New("signal failed"),
			pidExists: true,
			wantErr:   true,
		},
		{
			name:      "pid not found",
			signalErr: nil,
			pidExists: false,
			wantErr:   true,
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			mock := NewMockExecutor()
			mock.SignalErr = tc.signalErr

			var pid workspaceapi.Pid
			if tc.pidExists {
				var err error
				pid, err = mock.Start(context.Background(), workspaceapi.Cmd{Path: "/bin/sleep"})
				require.NoError(t, err)
			} else {
