package sandbox

import "github.com/unstablebuild/rune-go-sdk/sandbox/policy"

// Config contains configuration for creating a sandbox executor.
type Config struct {
	// WorkspaceRoot is the path to the workspace directory to mount in the VM.
	WorkspaceRoot string

	// Policy contains security policies for the sandbox.
	Policy *policy.Policy

	// Resources contains resource limits for the sandbox VM.
	Resources *ResourceConfig

	// Image is the path to the VM image to use.
	// If empty, a default image will be used.
	Image string
}

// ResourceConfig contains resource limits for a sandbox VM.
type ResourceConfig struct {
	// CPUs is the number of virtual CPUs to allocate.
	// Default: 1
	CPUs int

	// MemoryMB is the amount of memory in megabytes to allocate.
	// Default: 512
	MemoryMB int

	// DiskMB is the amount of disk space in megabytes to allocate.
	// Default: 1024
	DiskMB int
}

// DefaultConfig returns a Config with secure defaults.
func DefaultConfig() Config {
	return Config{
		Policy:    policy.DefaultPolicy(),
		Resources: DefaultResourceConfig(),
	}
}

// DefaultResourceConfig returns a ResourceConfig with sensible defaults.
func DefaultResourceConfig() *ResourceConfig {
	return &ResourceConfig{
		CPUs:     1,
		MemoryMB: 512,
		DiskMB:   1024,
	}
}

